"use strict";(self.webpackChunkbcsd_blog=self.webpackChunkbcsd_blog||[]).push([[6313],{3840:n=>{n.exports=JSON.parse('{"blogPosts":[{"id":"/posts/introduce-Android-2025","metadata":{"permalink":"/android/posts/introduce-Android-2025","source":"@site/@android/posts/introduce-Android-2025.mdx","title":"BCSD \uac00\uc774\ub4dc: \uc548\ub4dc\ub85c\uc774\ub4dc","description":"\uc548\ub4dc\ub85c\uc774\ub4dc \ud2b8\ub799\uc744 \uc18c\uac1c\ud569\ub2c8\ub2e4!","date":"2025-05-05T00:00:00.000Z","tags":[{"label":"Android","permalink":"/android/tags/android"},{"label":"\ud2b8\ub799 \uc18c\uac1c","permalink":"/android/tags/\ud2b8\ub799-\uc18c\uac1c"}],"readingTime":5.45,"hasTruncateMarker":true,"authors":[{"name":"WooJin Kong","url":"https://github.com/kongwoojin","email":"kongwoojin03@gmail.com","imageURL":"https://avatars.githubusercontent.com/u/20942714?v=4","key":"kongwoojin"}],"frontMatter":{"date":"2025-05-05T00:00:00.000Z","authors":"kongwoojin","title":"BCSD \uac00\uc774\ub4dc: \uc548\ub4dc\ub85c\uc774\ub4dc","description":"\uc548\ub4dc\ub85c\uc774\ub4dc \ud2b8\ub799\uc744 \uc18c\uac1c\ud569\ub2c8\ub2e4!","keywords":["Android","\ud2b8\ub799 \uc18c\uac1c"],"tags":["Android","\ud2b8\ub799 \uc18c\uac1c"]},"unlisted":false,"nextItem":{"title":"[FCM] Remote Data message","permalink":"/android/jokwanhee/jkh_fcm_data_message"}},"content":"\uc548\ub4dc\ub85c\uc774\ub4dc \ud2b8\ub799\uc744 \uc18c\uac1c\ud569\ub2c8\ub2e4!\\n\\n{/* truncate */}\\n\\n# **BCSD Android Track Introduce**\\n\\n\uc548\ub4dc\ub85c\uc774\ub4dc \ud2b8\ub799\uc5d0 \uc9c0\uc6d0\ud574\uc8fc\uc2e0 \uc5ec\ub7ec\ubd84, \uc9c4\uc2ec\uc73c\ub85c \ud658\uc601\ud569\ub2c8\ub2e4!\\n\\n\uc800\ud76c \uc548\ub4dc\ub85c\uc774\ub4dc \ud2b8\ub799\uc740 \uc804 \uc138\uacc4 \ubaa8\ubc14\uc77c OS \uc810\uc720\uc728\uc758 \uc57d 70%\ub97c \ucc28\uc9c0\ud558\uace0 \uc788\ub294 **\uc548\ub4dc\ub85c\uc774\ub4dc \uc571 \uac1c\ubc1c**\uc744 \uc911\uc2ec\uc73c\ub85c \ud65c\ub3d9\ud558\uace0 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n---\\n\\n## **Q. \uc548\ub4dc\ub85c\uc774\ub4dc\ub780 \ubb34\uc5c7\uc778\uac00\uc694?**\\n\\n\uc548\ub4dc\ub85c\uc774\ub4dc\ub294 \uad6c\uae00\uc5d0\uc11c \uac1c\ubc1c\ud55c \ubaa8\ubc14\uc77c\uc6a9 \uc6b4\uc601\uccb4\uc81c\ub85c,\\n\\n\uc804 \uc138\uacc4 \ubaa8\ubc14\uc77c \uc2dc\uc7a5\uc5d0\uc11c \uc57d 70%\uc758 \uc810\uc720\uc728\uc744 \ucc28\uc9c0\ud558\uace0 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n---\\n\\n## **Q. \uc5b4\ub5a4 \uc5b8\uc5b4\ub97c \uc0ac\uc6a9\ud558\ub098\uc694?**\\n\\n\uc800\ud76c\ub294 **Kotlin**\uc774\ub77c\ub294 \uc5b8\uc5b4\ub97c \uc0ac\uc6a9\ud569\ub2c8\ub2e4.\\n\\nKotlin\uc740 Jetbrains\uc0ac\uc5d0\uc11c \uac1c\ubc1c\ud55c \uac1d\uccb4\uc9c0\ud5a5 \ud504\ub85c\uadf8\ub798\ubc0d \uc5b8\uc5b4\ub85c, \uc790\ubc14\uc640 100% \ud638\ud658\ub418\ub294 \uc5b8\uc5b4\uc785\ub2c8\ub2e4.\\n\\n---\\n\\n## **Q. \uc548\ub4dc\ub85c\uc774\ub4dc \ud2b8\ub799\uc5d0\uc11c\ub294 \ubb34\uc5c7\uc744 \ud558\ub098\uc694?**\\n\\n\uc548\ub4dc\ub85c\uc774\ub4dc \ud2b8\ub799\uc5d0\uc11c\ub294\\n\\n**\uc548\ub4dc\ub85c\uc774\ub4dc \uc571\uc744 \uc9c1\uc811 \uac1c\ubc1c\ud558\uace0, Play \uc2a4\ud1a0\uc5b4\uc5d0 \ubc30\ud3ec\ud558\ub294 \uc77c\ub828\uc758 \uacfc\uc815\uc744 \uacbd\ud5d8**\ud558\uac8c \ub429\ub2c8\ub2e4.\\n\\n---\\n\\n## **Q. \ubaa8\ubc14\uc77c \uac8c\uc784 \uac1c\ubc1c\ub3c4 \ubc30\uc6b0\ub098\uc694?**\\n\\n\uc544\uc27d\uac8c\ub3c4 \uc548\ub4dc\ub85c\uc774\ub4dc \ud2b8\ub799\uc5d0\uc11c\ub294 \ubaa8\ubc14\uc77c \uac8c\uc784 \uac1c\ubc1c\uc744 \ub2e4\ub8e8\uc9c0 \uc54a\uc2b5\ub2c8\ub2e4.\\n\\n\uac8c\uc784 \uac1c\ubc1c\uc5d0 \uad00\uc2ec\uc774 \uc788\uc73c\uc2dc\ub2e4\uba74 **\uac8c\uc784 \ud2b8\ub799**\uc5d0 \uc9c0\uc6d0\ud574\uc8fc\uc2dc\uba74 \uc88b\uaca0\uc2b5\ub2c8\ub2e4.\\n\\n---\\n\\n## **Q. Java\ub9cc \ud574\ubd24\ub294\ub370, \ub610\ub294 Kotlin\uc774 \ucc98\uc74c\uc778\ub370 \ub530\ub77c\uac00\uae30 \ud798\ub4e4\uae4c\uc694?**\\n\\nKotlin\uc740 JVM \uc5b8\uc5b4\uc774\uc9c0\ub9cc, Java\uc640 \ubb38\ubc95\uc774 \ub2e4\ub974\uae30 \ub54c\ubb38\uc5d0 Java \uacbd\ud5d8\uc774 \ud06c\uac8c \ub3c4\uc6c0\uc774 \ub418\uc9c0\ub294 \uc54a\uc744 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\ud558\uc9c0\ub9cc Kotlin\uc740 \ube44\uad50\uc801 \ubc30\uc6b0\uae30 \uc26c\uc6b4 \uc5b8\uc5b4\ub77c, \ucc98\uc74c \uc811\ud558\uc2dc\ub354\ub77c\ub3c4 \ucda9\ubd84\ud788 \ub530\ub77c\uc624\uc2e4 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n---\\n\\n## **Q. \ub204\uad6c\uc640 \ud611\uc5c5\ud558\uac8c \ub418\ub098\uc694?**\\n\\n\uc800\ud76c\ub294 **\ubc31\uc5d4\ub4dc \uac1c\ubc1c\uc790, \ub514\uc790\uc774\ub108, PM** \ub4f1 \ub2e4\uc591\ud55c \uc5ed\ud560\uc758 \ud300\uc6d0\ub4e4\uacfc \ud611\uc5c5\ud569\ub2c8\ub2e4.\\n\\n---\\n\\n## **Q. Flutter\ub098 React Native\ub3c4 \uc0ac\uc6a9\ud558\ub098\uc694?**\\n\\n\uc800\ud76c \ud2b8\ub799\uc5d0\uc11c\ub294 **Flutter\ub098 React Native\ub294 \uc0ac\uc6a9\ud558\uc9c0 \uc54a\uace0, Kotlin\uc744 \ud65c\uc6a9\ud55c \ub124\uc774\ud2f0\ube0c \uc571 \uac1c\ubc1c**\ub9cc \uc9c4\ud589\ud569\ub2c8\ub2e4.\\n\\n---\\n\\n## **Q. \ud504\ub860\ud2b8\uc5d4\ub4dc\uc640\ub294 \ubb34\uc5c7\uc774 \ub2e4\ub978\uac00\uc694?**\\n\\n\ud074\ub77c\uc774\uc5b8\ud2b8 \uac1c\ubc1c\uc774\ub77c\ub294 \uc810\uc5d0\uc11c \ud504\ub860\ud2b8\uc5d4\ub4dc\uc640 \uc720\uc0ac\ud558\uc9c0\ub9cc,\\n\\n\uc6f9\uacfc \ubaa8\ubc14\uc77c \ud50c\ub7ab\ud3fc\uc758 \ucc28\uc774\ub85c \uc778\ud574 \uac1c\ubc1c \ubc29\uc2dd\uacfc \ub3c4\uad6c, \uad6c\ud604 \ubc29\uc2dd\uc5d0\uc11c \ucc28\uc774\uac00 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n---\\n\\n## **Q. iOS \ud2b8\ub799\uacfc\ub294 \uc5b4\ub5a4 \uc810\uc774 \ub2e4\ub974\ub098\uc694?**\\n\\n\uc548\ub4dc\ub85c\uc774\ub4dc \ud2b8\ub799\uacfc iOS \ud2b8\ub799 \ubaa8\ub450 \ubaa8\ubc14\uc77c \uc571 \uac1c\ubc1c\uc744 \ubaa9\ud45c\ub85c \ud558\uc9c0\ub9cc,\\n\\n\ud50c\ub7ab\ud3fc\uc774 \ub2e4\ub974\uae30 \ub54c\ubb38\uc5d0 \uc0ac\uc6a9\ud558\ub294 \uc5b8\uc5b4\ub098 \uac1c\ubc1c \ub3c4\uad6c\uc5d0\ub3c4 \ucc28\uc774\uac00 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n---\\n\\n## **Q. \ube44\uae30\ub108 \uacfc\uc815\uc740 \uc5b4\ub5bb\uac8c \uc9c4\ud589\ub418\ub098\uc694?**\\n\\n\uc548\ub4dc\ub85c\uc774\ub4dc \ud2b8\ub799 \ube44\uae30\ub108 \uacfc\uc815\uc740 <strong>\ucd1d 17\uc8fc(13\uc8fc \uad50\uc721 + 3\uc8fc \uc790\uc728 \ud504\ub85c\uc81d\ud2b8 + 1\uc8fc \ud68c\uace0)</strong>\ub85c \uc774\ub8e8\uc5b4\uc838 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\ucf54\ud2c0\ub9b0 \uc5b8\uc5b4\uc758 \uae30\ucd08\ubd80\ud130 \uc548\ub4dc\ub85c\uc774\ub4dc \uc571 \uac1c\ubc1c \ubc29\ubc95, \uadf8\ub9ac\uace0 \ub2e4\ub978 \uac1c\ubc1c\uc790\uc640 \ud611\uc5c5\ud558\ub294 \ubc29\ubc95\uae4c\uc9c0 \ub2e8\uacc4\uc801\uc73c\ub85c \ubc30\uc6c1\ub2c8\ub2e4.\\n\\n---\\n\\n## **Q. \ub808\uade4\ub7ec\ub85c\ub294 \uc5b4\ub5bb\uac8c \uc804\ud658\ub418\ub098\uc694?**\\n\\n\ube44\uae30\ub108 \uad50\uc721\uacfc\uc815\uc744 \uc131\uacf5\uc801\uc73c\ub85c \uc774\uc218\ud558\uace0, \uadf8 \uacfc\uc815\uc5d0\uc11c \ubc30\uc6b4 \ub0b4\uc6a9\uc744 \ubc14\ud0d5\uc73c\ub85c **\ud68c\uace0 \ud504\ub85c\uc81d\ud2b8**\ub97c \uc9c4\ud589\ud569\ub2c8\ub2e4.\\n\\n\ud68c\uace0\ub97c \uc131\uacf5\uc801\uc73c\ub85c \ub9c8\uce58\uba74 \ub808\uade4\ub7ec\ub85c \uc804\ud658\ub429\ub2c8\ub2e4.\\n\\n---\\n\\n## **Q. \ub808\uade4\ub7ec\uac00 \ub418\uba74 \ubb34\uc5c7\uc744 \ud558\ub098\uc694?**\\n\\n\ub808\uade4\ub7ec\ub85c \uc804\ud658\ub418\uba74, **BCSDLab\uc5d0\uc11c \uc9c4\ud589 \uc911\uc778 \uc2e4\uc81c \ud504\ub85c\uc81d\ud2b8(\ud604\uc7ac\ub294 \ucf54\uc778 \ud504\ub85c\uc81d\ud2b8)**\uc5d0 \ud22c\uc785\ub418\uc5b4 \uc2e4\uc804 \uacbd\ud5d8\uc744 \uc313\uac8c \ub429\ub2c8\ub2e4.\\n\\n---\\n\\n## **Q. \ub9ce\uc774 \uc5b4\ub835\ub098\uc694?**\\n\\n\uc0ac\ub78c\ub9c8\ub2e4 \ub2e4\ub974\uc9c0\ub9cc \uc0c8\ub85c\uc6b4 \uac83\uc744 \ubc30\uc6b0\ub294 \uacfc\uc815\uc774\uae30 \ub54c\ubb38\uc5d0 \uc27d\uc9c0\ub294 \uc54a\uc744 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\ud558\uc9c0\ub9cc \ucee4\ub9ac\ud058\ub7fc\uc744 \uc131\uc2e4\ud788 \ub530\ub77c\uc624\uc2e0\ub2e4\uba74 \ucda9\ubd84\ud788 \ud574\ub0bc \uc218 \uc788\uc73c\ub2c8 \uac71\uc815\ud558\uc9c0 \uc54a\uc73c\uc154\ub3c4 \uad1c\ucc2e\uc2b5\ub2c8\ub2e4!\\n\\n---\\n\\n## **\ub9c8\ubb34\ub9ac**\\n\\n\ucc98\uc74c\uc5d0\ub294 \uc775\uc219\ud558\uc9c0 \uc54a\uc740 \uc5b8\uc5b4\ub098 \ub3c4\uad6c, \uc0c8\ub85c\uc6b4 \uac1c\ubc1c \ud658\uacbd\uc774 \ubd80\ub2f4\uc2a4\ub7fd\uac8c \ub290\uaef4\uc9c8 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\ud558\uc9c0\ub9cc \ud55c \ub2e8\uacc4\uc529 \ucc28\uadfc\ucc28\uadfc \ub530\ub77c\uac00\ub2e4 \ubcf4\uba74, \ubd84\uba85\ud788 \uc2e4\ub825\uc774 \uc313\uc774\uace0 \uc788\ub2e4\ub294 \uac83\uc744 \ub290\ub07c\uac8c \ub420 \uac70\uc608\uc694.\\n\\n\ubaa8\ub974\ub294 \uac8c \uc788\uc73c\uba74 \uc5b8\uc81c\ub4e0\uc9c0 \ubb3c\uc5b4\ubcf4\uc154\ub3c4 \uc88b\uc544\uc694!"},{"id":"/jokwanhee/jkh_fcm_data_message","metadata":{"permalink":"/android/jokwanhee/jkh_fcm_data_message","source":"@site/@android/jokwanhee/jkh_fcm_data_message.mdx","title":"[FCM] Remote Data message","description":"\uc548\ub4dc\ub85c\uc774\ub4dc\uc5d0\uc11c FCM \uba54\uc2dc\uc9c0 Data \ud398\uc774\ub85c\ub4dc \uad00\ub828\ud574\uc11c \ub2e4\ub8f9\ub2c8\ub2e4.","date":"2024-10-07T00:00:00.000Z","tags":[{"label":"\uc548\ub4dc\ub85c\uc774\ub4dc","permalink":"/android/tags/\uc548\ub4dc\ub85c\uc774\ub4dc"},{"label":"FCM","permalink":"/android/tags/fcm"}],"readingTime":4.71,"hasTruncateMarker":true,"authors":[{"name":"JoKwanhee","url":"https://github.com/Jokwanhee","email":"jonotch1@naver.com","imageURL":"https://avatars.githubusercontent.com/u/90740783?v=4","key":"jokwanhee"}],"frontMatter":{"date":"2024-10-07T00:00:00.000Z","authors":"jokwanhee","title":"[FCM] Remote Data message","description":"\uc548\ub4dc\ub85c\uc774\ub4dc\uc5d0\uc11c FCM \uba54\uc2dc\uc9c0 Data \ud398\uc774\ub85c\ub4dc \uad00\ub828\ud574\uc11c \ub2e4\ub8f9\ub2c8\ub2e4.","keywords":["\uc548\ub4dc\ub85c\uc774\ub4dc","FCM"],"tags":["\uc548\ub4dc\ub85c\uc774\ub4dc","FCM"]},"unlisted":false,"prevItem":{"title":"BCSD \uac00\uc774\ub4dc: \uc548\ub4dc\ub85c\uc774\ub4dc","permalink":"/android/posts/introduce-Android-2025"},"nextItem":{"title":"[FCM] Remote Notification Message","permalink":"/android/jokwanhee/jkh_fcm_notification_message"}},"content":"\uc548\ub4dc\ub85c\uc774\ub4dc\uc5d0\uc11c FCM\uc744 \uc0ac\uc6a9\ud588\uc744 \ub54c, \uba54\uc2dc\uc9c0\ub97c \ubc1b\uc2b5\ub2c8\ub2e4.  \\n\ud574\ub2f9 \uba54\uc2dc\uc9c0\uc758 \ud544\ub4dc\uac00 Data \ud398\uc774\ub85c\ub4dc\uc778 \uac83\uc5d0 \ub300\ud574\uc11c \ub2e4\ub8f9\ub2c8\ub2e4.\\n\\n{/* truncate */}\\n\\nFCM \uc54c\ub9bc\uc744 \uad6c\ud604\ud558\uba74\uc11c notficatioin \ud398\uc774\ub85c\ub4dc\ub97c \ubc1b\uc9c0 \uc54a\uace0, data \ud398\uc774\ub85c\ub4dc\ub9cc \ubc1b\uac8c \ub41c\ub2e4\uba74 \uc5b4\ub5bb\uac8c \ud560\uae4c\uc694?\\n\\n\uc774\ub294 \ubc31\uadf8\ub77c\uc6b4\ub4dc \ud478\uc2dc \uc54c\ub9bc\uc73c\ub85c \uad6c\ud604\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n:::tip\\n\ubc31\uadf8\ub77c\uc6b4\ub4dc \ud478\uc2dc \uc54c\uc544\ubcf4\uace0 \ub118\uc5b4\uac00\uc790\\n:::\\n\\n\uc6b0\uc120 \uc0ac\uc6a9\ud558\ub294 \ubc29\ubc95\uc5d0 \ub300\ud574\uc11c \ub9d0\ud558\uae30 \uc804\uc5d0 TMI \ub97c \ud558\uaca0\uc2b5\ub2c8\ub2e4.\\n\\n\uc800\ub294 data \ud398\uc774\ub85c\ub4dc\ub97c \uc0ac\uc6a9\ud574\uc11c \ubc31\uadf8\ub77c\uc6b4\ub4dc\uc5d0\uc11c data \ud398\uc774\ub85c\ub4dc\ub97c \uc0ac\uc6a9\ud558\uc5ec \uc54c\ub9bc\uc744 \ub098\ud0c0\ub0b4\ub294 \uac83\uc744 \uc0ac\uc77c\ub7f0\ud2b8 \ud478\uc2dc\ub77c\ub294 \uc6a9\uc5b4\ub77c\uace0 \uc54c\uace0 \uc788\uc5c8\uc2b5\ub2c8\ub2e4.\\n\\n\uc989, \uc77c\ubc18\uc801\uc73c\ub85c \uc0ac\uc6a9\uc790\uc5d0\uac8c \uc2dc\uac01\uc801 \uc54c\ub9bc\uc744 \ud45c\uc2dc\ud558\uc9c0 \uc54a\uace0 \ub370\uc774\ud130\ub97c \ucc98\ub9ac\ud560 \uc218 \uc788\ub294 \ud478\uc2dc \uc54c\ub9bc\uc785\ub2c8\ub2e4.\\n\\n\ud558\uc9c0\ub9cc \uc0ac\uc77c\ub7f0\ud2b8 \ud478\uc2dc\ub77c\ub294 \uac1c\ub150\uc774 \uc548\ub4dc\ub85c\uc774\ub4dc\uc5d0\uc11c\ub294 \uc0ac\uc6a9\ud558\uc9c0 \uc54a\uace0, iOS\uc5d0\uc11c \uc0ac\uc6a9\ub418\uc5c8\uae30\uc5d0 \uc800\ub294 \ub611\uac19\ub2e4\uace0 \ud310\ub2e8\ud558\uc5ec \uc548\ub4dc\ub85c\uc774\ub4dc\uc5d0\uc11c\ub3c4 data \ud544\ub4dc\ub97c \uc0ac\uc6a9\ud558\ub294 \ud478\uc2dc \uc54c\ub9bc\uc744 \uc0ac\uc77c\ub7f0\ud2b8 \ud478\uc2dc\ub77c\uace0 \uc815\uc758\ud588\uc2b5\ub2c8\ub2e4.\\n\\n\ud558\uc9c0\ub9cc \uc774 \ub9d0\uc740 \ub9de\uc73c\uba74\uc11c \ud2c0\ub9bd\ub2c8\ub2e4.\\n\\n\uc6b0\uc120 \ub73b\uc740 \uc77c\uce58\ud569\ub2c8\ub2e4.  \\n\uc2dc\uac01\uc801 \uc54c\ub9bc\uc744 \ud45c\uc2dc\ud558\uc9c0 \uc54a\uace0, \ub370\uc774\ud130\ub97c \ubc31\uadf8\ub77c\uc6b4\ub4dc\uc5d0\uc11c \uc9c1\uc811 \ucc98\ub9ac\ud560 \uc218 \uc788\ub294 \ud478\uc2dc \uc54c\ub9bc\uc774 \uc0ac\uc77c\ub7f0\ud2b8 \ud478\uc2dc\uc785\ub2c8\ub2e4.  \\n\ud558\uc9c0\ub9cc \uc774 \uc6a9\uc5b4\ub294 iOS\uc5d0\uc11c \uc0ac\uc77c\ub7f0\ud2b8 \ud478\uc2dc\ub77c\ub294 \uc6a9\uc5b4\ub97c \uc0ac\uc6a9\ud558\uba70, Android \uc5d0\uc11c\ub294 Remote data message \ub77c\ub294 \uc6a9\uc5b4\ub97c \uc0ac\uc6a9\ud569\ub2c8\ub2e4.\\n\\n\ud574\ub2f9 \uc6a9\uc5b4\uac00 \ud5f7\uac08\ub838\uc9c0\ub9cc \ud574\ub2f9 [\uc544\ud2f0\ud074](https://velog.io/@bang9dev/RN-CheatSheet-push-notification-%EC%99%84%EB%B2%BD-%EC%9D%B4%ED%95%B4%ED%95%98%EA%B8%B0)\ub97c \ubcf4\uba74\uc11c \uc774\ud574\ud560 \uc218 \uc788\uc5c8\uc2b5\ub2c8\ub2e4.\\n\\n\\n## data \ud398\uc774\ub85c\ub4dc\\n\\n\uc548\ub4dc\ub85c\uc774\ub4dc\uc5d0\uc11c\ub294 FCM \uba54\uc2dc\uc9c0 \ud615\uc2dd\uc744 \ubc1b\uc744 \ub54c, notification \ud398\uc774\ub85c\ub4dc\ub97c \ubc1b\uc73c\uba74 \uc571\uc774 \ubc31\uadf8\ub77c\uc6b4\ub4dc \uc0c1\ud0dc\uc77c \ub54c \uc2dc\uc2a4\ud15c \ud2b8\ub808\uc774\uc5d0\uc11c \uc54c\ub9bc\uc744 \ub744\uc6cc\uc90d\ub2c8\ub2e4.\\n\\n\ud558\uc9c0\ub9cc notification \ud398\uc774\ub85c\ub4dc\uac00 \uc5c6\ub2e4\uba74, data \ud398\uc774\ub85c\ub4dc \ub370\uc774\ud130\ub97c \uac00\uacf5\ud574\uc11c \uc9c1\uc811 \ucee4\uc2a4\ud140 \uc54c\ub9bc\uc744 \uc81c\uc791\ud574\uc8fc\uc5b4\uc57c \ud569\ub2c8\ub2e4.\\n\\n\uc5b4\ub5bb\uac8c \ucf54\ub4dc\ub97c \uad6c\ud604\ud560\uc9c0 \uace0\ubbfc\ud574\ubd05\uc2dc\ub2e4.\\n\\n\uc6b0\uc120, `FirebaseMessagingService` \uc11c\ube44\uc2a4\ub97c \ub9cc\ub4e0 \ub4a4 \ud574\ub2f9 \ud074\ub798\uc2a4\uc5d0\uc11c \uba54\uc2dc\uc9c0\ub97c \ubc1b\uc544\ubcfc \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\ndata \ud544\ub4dc\ub9cc \uc874\uc7ac\ud558\ub294 \uba54\uc2dc\uc9c0\ub97c \ubc1b\uc744 \ub54c\ub294 \uc571\uc774 \ubc31\uadf8\ub77c\uc6b4\ub4dc \uc0c1\ud0dc\uc77c \ub54c\ub098 \ud3ec\uadf8\ub77c\uc6b4\ub4dc \uc0c1\ud0dc\uc77c \ub54c\ub098 \uc0c1\uad00\uc5c6\uc774 \ud574\ub2f9 \uc11c\ube44\uc2a4 \ud074\ub798\uc2a4\uc5d0\uc11c \ub370\uc774\ud130\ub97c \ubc1b\uc544\ubcfc \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\uc608\uc2dc\ub85c \ub85c\uceec \uc11c\ubc84\uc5d0\uc11c \uc5b4\ub5a4 \uba54\uc2dc\uc9c0\ud615\uc2dd\uc744 \ubcf4\ub0c8\ub294 \uc9c0 \uc544\ub798\uc758 \ucf54\ub4dc\ub85c \uc0b4\ud3b4\ubd05\ub2c8\ub2e4.\\n\\n```kotlin\\n\\"data\\" : {\\n  \\"title\\" : \\"\uc81c\ubaa9\\",\\n  \\"body\\" : \\"\ub0b4\uc6a9\\",\\n  \\"url\\" : \\"koin://shop?id=1\\",\\n  \\"image\\" : \\"https://afaefwef.jpg\\"\\n}\\n```\\n\\n\uc548\ub4dc\ub85c\uc774\ub4dc\uc5d0\uc11c\ub294 \uc5b4\ub5bb\uac8c \ubc1b\uc544\ubcfc\uae4c\uc694?  \\n\uc544\ub798\uc758 \ub85c\uadf8\ub294 \uc571\uc774 \uc2e4\ud589\ub418\uc5b4\uc788\uac70\ub098 \ubc31\uadf8\ub77c\uc6b4\ub4dc \uc0c1\ud0dc\uc77c \ub54c \ub450 \uac00\uc9c0 \ubaa8\ub450 \ub85c\uadf8\ub97c \ud655\uc778\ud574\ubcfc \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n```kotlin\\noverride fun onMessageReceived(message: RemoteMessage) {\\n  super.onMessageReceived(message)\\n  \\n  message.data.let { data ->\\n      if (data.isNotEmpty()) {\\n          Log.e(\\"aaa\\", \\"message.data : $data\\")\\n      }\\n  }\\n}\\n```\\n```\\n>>>\\nmessage.data : {title=\uc81c\ubaa9, body=\ub0b4\uc6a9, url=koin://shop?id=1, image=https://afaefwef.jpg}\\n```\\n\uc704\uc640 \uac19\uc774 Map \ud615\uc2dd\uc73c\ub85c \ub370\uc774\ud130\ub97c \ubc1b\uc544\ubcfc \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\uc5ec\uae30\uc11c \uc774\uc81c \uc6d0\ud558\ub294 \uc54c\ub9bc \uad6c\ud604 \ucf54\ub4dc\ub97c \uc791\uc131\ud558\uace0, PendingIntent\ub97c \ub9cc\ub4e4\uc5b4 \ud074\ub9ad\ud588\uc744 \ub54c \uc6d0\ud558\ub294 \uc561\ud2f0\ube44\ud2f0\ub85c \uc774\ub3d9\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\uad6c\uccb4\uc801\uc778 \uad6c\ud604 \ubc29\ubc95\uc744 \ud655\uc778\ud558\uace0 \uc2f6\ub2e4\uba74, \ucf54\uc778 \uc548\ub4dc\ub85c\uc774\ub4dc \uae43\ud5c8\ube0c\uc5d0\uc11c \ud574\ub2f9 \ucf54\ub4dc\ub97c \ud655\uc778\ud574\ubcfc \uc218 \uc788\uc2b5\ub2c8\ub2e4.  \\n[\ucf54\uc778 \uc548\ub4dc\ub85c\uc774\ub4dc \uae43\ud5c8\ube0c \ubc14\ub85c\uac00\uae30](https://github.com/BCSDLab/KOIN_ANDROID)"},{"id":"/jokwanhee/jkh_fcm_notification_message","metadata":{"permalink":"/android/jokwanhee/jkh_fcm_notification_message","source":"@site/@android/jokwanhee/jkh_fcm_notification_message.mdx","title":"[FCM] Remote Notification Message","description":"\uc548\ub4dc\ub85c\uc774\ub4dc\uc5d0\uc11c FCM \uba54\uc2dc\uc9c0 Notification \ud398\uc774\ub85c\ub4dc \uad00\ub828\ud574\uc11c \ub2e4\ub8f9\ub2c8\ub2e4.","date":"2024-10-07T00:00:00.000Z","tags":[{"label":"\uc548\ub4dc\ub85c\uc774\ub4dc","permalink":"/android/tags/\uc548\ub4dc\ub85c\uc774\ub4dc"},{"label":"FCM","permalink":"/android/tags/fcm"}],"readingTime":7.255,"hasTruncateMarker":true,"authors":[{"name":"JoKwanhee","url":"https://github.com/Jokwanhee","email":"jonotch1@naver.com","imageURL":"https://avatars.githubusercontent.com/u/90740783?v=4","key":"jokwanhee"}],"frontMatter":{"date":"2024-10-07T00:00:00.000Z","authors":"jokwanhee","title":"[FCM] Remote Notification Message","description":"\uc548\ub4dc\ub85c\uc774\ub4dc\uc5d0\uc11c FCM \uba54\uc2dc\uc9c0 Notification \ud398\uc774\ub85c\ub4dc \uad00\ub828\ud574\uc11c \ub2e4\ub8f9\ub2c8\ub2e4.","keywords":["\uc548\ub4dc\ub85c\uc774\ub4dc","FCM"],"tags":["\uc548\ub4dc\ub85c\uc774\ub4dc","FCM"]},"unlisted":false,"prevItem":{"title":"[FCM] Remote Data message","permalink":"/android/jokwanhee/jkh_fcm_data_message"},"nextItem":{"title":"\ucf54\uc778 Gradle \uccad\uc18c \ud6c4\uae30","permalink":"/android/jokwanhee/jkh_gradle_cleanup"}},"content":"\uc548\ub4dc\ub85c\uc774\ub4dc\uc5d0\uc11c FCM\uc744 \uc0ac\uc6a9\ud588\uc744 \ub54c, \uba54\uc2dc\uc9c0\ub97c \ubc1b\uc2b5\ub2c8\ub2e4.  \\n\ud574\ub2f9 \uba54\uc2dc\uc9c0\uc758 \ud544\ub4dc\uac00 Notification \ud398\uc774\ub85c\ub4dc\uc778 \uac83\uc5d0 \ub300\ud574\uc11c \ub2e4\ub8f9\ub2c8\ub2e4.\\n\\n{/* truncate */}\\n\\n\\n\uc774\uc804\uc5d0 \ud3ec\uc2a4\ud305 [\uc548\ub4dc\ub85c\uc774\ub4dc \uac1c\ubc1c\uc790\uac00 \ubc14\ub77c\ubcf8 FCM \ud14c\uc2a4\ud2b8](https://blog.bcsdlab.com/android/react/jkh_fcm)\uc5d0\uc11c\ub294 notification \ud398\uc774\ub85c\ub4dc\ub97c \uc0ac\uc6a9\ud574\uc11c \uac04\ub2e8\ud558\uac8c \uc2dc\uc2a4\ud15c \ud2b8\ub808\uc774\uc5d0\uc11c \ubc1b\uc544\uc628 \uc54c\ub9bc\uc744 \uac00\uc9c0\uace0, \uc54c\ub9bc\uc744 \ub744\uc6b0\ub294 \uac83\uc744 \ud574\ubd24\uc2b5\ub2c8\ub2e4.\\n\\n\ud574\ub2f9 \ud3ec\uc2a4\ud305\uc5d0\uc11c\ub294 notification & data \ud544\ub4dc\uc758 \uba54\uc2dc\uc9c0\uac00 \uc62c \ub54c, \uc5b4\ub5bb\uac8c \ucc98\ub9ac\ud560 \uc218 \uc788\ub294\uc9c0 \uc54c\uc544\ubcf4\ub294 \uc2dc\uac04\uc744 \uac00\uc9c0\ub824\uace0 \ud569\ub2c8\ub2e4.\\n\\n## notification & data \ud398\uc774\ub85c\ub4dc\\n\\n\uc624\ub298\uc740 notification & data \ud398\uc774\ub85c\ub4dc\uac00 \uac19\uc774\uc62c \ub54c, \uc5b4\ub5bb\uac8c \ud478\uc2dc \uc54c\ub9bc\uc744 \ucc98\ub9ac\ud574\uc57c\ud558\ub294 \uc9c0 \uc54c\uc544\ubcf4\uaca0\uc2b5\ub2c8\ub2e4.\\n\\nnotification & data \ud398\uc774\ub85c\ub4dc\uac00 \uac19\uc774\uc624\uba74, \uc571\uc5d0\uc11c\ub294 \uc5b4\ub5bb\uac8c \ub370\uc774\ud130\ub97c \ubc1b\uac8c\ub420\uae4c\uc694?  \\n\uc6b0\uc120, notification \uc5d0\uc11c \ubc1b\ub294 \ud398\uc774\ub85c\ub4dc\ub85c \uc54c\ub9bc\uc744 \uc2dc\uc2a4\ud15c \ud2b8\ub808\uc774\uc5d0\uc11c \ub744\uc6b0\uac8c \ub429\ub2c8\ub2e4.\\n\\n:::info\\n\uc2dc\uc2a4\ud15c \ud2b8\ub808\uc774\uc5d0\uc11c \ub744\uc6b4\ub2e4\ub294 \uac83\uc740 \ub530\ub85c \uc54c\ub9bc\uc744 \uad6c\ud604\ud558\uc9c0 \uc54a\uc544\ub3c4 \uc790\uccb4\uc801\uc73c\ub85c \uc54c\ub9bc\uc774 Notification \ud544\ub4dc\uc758 \ub370\uc774\ud130\ub97c \uac00\uc9c0\uace0 \uc81c\ubaa9, \ubcf8\ubb38\uc744 \ucc44\uc6cc \uc54c\ub9bc\uc744 \ub744\uc6b4\ub2e4\ub294 \uac83\uc785\ub2c8\ub2e4.\\n:::\\n\\n### \uc571\uc774 \uc2e4\ud589\ub41c \uc0c1\ud0dc\uc77c \ub54c\ub294?\\n\\n\uc571\uc774 \uc2e4\ud589\ub418\uace0 \uc788\uc744 \ub54c\ub294 \uc5b4\ub5a8\uae4c\uc694? \uc571\uc774 \uc2e4\ud589\ub418\uc5c8\uc744 \ub54c\ub294 \uc2dc\uc2a4\ud15c \ud2b8\ub808\uc774\uc5d0\uc11c \uc54c\ub9bc\uc744 \ub744\uc6b0\uc9c0 \uc54a\uc2b5\ub2c8\ub2e4. \ud558\uc9c0\ub9cc \uba54\uc2dc\uc9c0 \ud398\uc774\ub85c\ub4dc\ub97c \ub85c\uae45\uc73c\ub85c \ucc0d\uc5b4\ubcfc \uc218 \uc788\uc2b5\ub2c8\ub2e4.   \\n\ud574\ub2f9 \uba54\uc2dc\uc9c0 \ud398\uc774\ub85c\ub4dc\ub294 `FirebaseMessagingService`\ub97c \uc0c1\uc18d\ubc1b\ub294 \uc11c\ube44\uc2a4 \ud074\ub798\uc2a4\uc5d0\uc11c \ub370\uc774\ud130\ub97c \ubc1b\uc544\ubcfc \uc218 \uc788\uc2b5\ub2c8\ub2e4. \uadf8\ub807\ub2e4\ub294 \uac83\uc740 \uc571\uc774 \uc2e4\ud589\ub418\uace0 \uc788\uc744 \ub54c, \uc790\uccb4\uc801\uc73c\ub85c \uc54c\ub9bc\uc744 \uad6c\ud604\ud574\uc57c\ud55c\ub2e4\ub294 \uac83\uc785\ub2c8\ub2e4. \ucf54\ub4dc \uc9dc\uc2dc\uba74 \ub429\ub2c8\ub2e4.\\n\\n\uac04\ub2e8\ud55c \uc608\uc2dc\ub97c \uc0b4\ud3b4\ubcf4\uba74, \uc11c\ubc84\uc5d0\uc11c \uc804\ub2ec\ud574\uc8fc\ub294 \uba54\uc2dc\uc9c0 \ud615\uc2dd\uc740 \ub2e4\uc74c\uacfc \uac19\uc2b5\ub2c8\ub2e4.\\n```kotlin\\n\\"notification\\" : {\\n  \\"title\\" : \\"a\\",\\n  \\"body\\" : \\"b\\",\\n  \\"click_action\\" : \\"shop\\"\\n}\\n\\n\\"data\\" : {\\n  \\"data_title\\" : \\"title\\",\\n  \\"data_type\\" : \\"type\\"\\n}\\n```\\n\\n`FirebaseMessagingService` \uc11c\ube44\uc2a4 \uad6c\ud604\uccb4 \ud074\ub798\uc2a4\ub294 \uc544\ub798\uc640 \uac19\uc774 \uc791\uc131\ud569\ub2c8\ub2e4. \uc544\ub798 \ucf54\ub4dc\ub97c \ubcf4\uba74 \uc5b4\ub514\uc11c notification\uacfc data \uba54\uc2dc\uc9c0 \ub85c\uae45\uc744 \ud655\uc778\ud574\ubcfc \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n```kotlin\\noverride fun onMessageReceived(message: RemoteMessage) {\\n  super.onMessageReceived(message)\\n  message.data.let { data ->\\n      if (data.isNotEmpty()) {\\n          Log.e(\\"aaa\\", \\"message.data : $data\\")\\n      }\\n  }\\n  \\n  message.notification?.let { notification ->\\n      Log.e(\\"aaa\\", \\"notification.title : ${notification.title}\\")\\n      Log.e(\\"aaa\\", \\"notification.body : ${notification.body}\\")\\n      Log.e(\\"aaa\\", \\"notification.clickAction : ${notification.clickAction}\\")\\n  }\\n}\\n```\\n```\\n>>>\\nmessage.data : {data_type=type, data_title=title}\\nnotification.title : a\\nnotification.body : b\\nnotification.clickAction : shop\\n```\\n\\n\uadf8\ub807\ub2e4\uba74, \uc571\uc774 \uaebc\uc838\uc788\uc744 \ub54c \uc989, \ubc31\uadf8\ub77c\uc6b4\ub4dc \uc0c1\ud0dc\uc77c \ub54c\ub294 \uc5b4\ub5a8\uae4c\uc694?\\n\\n### \uc571\uc774 \ubc31\uadf8\ub77c\uc6b4\ub4dc \uc0c1\ud0dc\uc77c \ub54c\ub294?\\n\\n\ubc31\uadf8\ub77c\uc6b4\ub4dc\uc5d0 \uc788\uc744 \ub54c\ub294 `FirebaseMessagingService` \uc5d0\uc11c \ub370\uc774\ud130\ub97c \ucc0d\uc5b4\ubcfc \uc218 \uc5c6\uc2b5\ub2c8\ub2e4. \\n\uc2dc\uc2a4\ud15c \ud2b8\ub808\uc774\uc5d0\uc11c notification \ud398\uc774\ub85c\ub4dc\ub85c \uc54c\ub9bc\uc744 \ub744\uc6b0\uac8c \ub429\ub2c8\ub2e4.\\n\\n\uadf8\ub807\ub2e4\uba74 \uc54c\ub9bc\uc744 \ud074\ub9ad\ud588\uc744 \ub54c\uc758 \ud578\ub4e4\ub9c1\uc744 \ud558\uc5ec \ub124\ube44\uac8c\uc774\uc158\ud560 \uc218 \uc5c6\uc744\uae4c\uc694?  \\n\uc544\ub1e8. \ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \ub370\uc774\ud130\ub97c \ucc0d\uc5b4\ubcfc \uc218 \uc5c6\ub2e4\uace0 \ud588\ub294\ub370, \uc54c\ub9bc\uc744 \ud074\ub9ad\ud588\uc744 \ub54c \uc5b4\ub5bb\uac8c \ub124\ube44\uac8c\uc774\uc154\ub2dd \ud560 \uc218 \uc788\uc744\uae4c\uc694?\\n\\n\uc54c\ub9bc\uc744 \ud074\ub9ad\ud588\uc744 \ub54c, \uc2dc\uc2a4\ud15c \ud2b8\ub808\uc774\uc5d0\uc11c\ub294 click_action \uc774\ub77c\ub294 \uac12\uc744 \ubc1b\uc544 \ud578\ub4e4\ub9c1\ud558\uac8c \ub429\ub2c8\ub2e4. \uadf8\ub9ac\uace0 `Manifest.xml` \uc5d0\uc11c \ud574\ub2f9 click_action \uc5d0 \uac12\uc744 \ub123\uc73c\uba74 \uc6d0\ud558\ub294 \uc561\ud2f0\ube44\ud2f0\ub85c \uc774\ub3d9\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\uc74c? \uadf8\ub807\ub2e4\uba74 \ud504\ub798\uadf8\uba3c\ud2b8\ub85c \uc774\ub3d9\ud558\uace0 \uc2f6\uc744 \ub54c\ub294 \ubabb\ud558\uac8c \ub418\ub294 \uac74\uac00\uc694? \ub77c\ub294 \uc9c8\ubb38\uc744 \ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\ud574\ub2f9 \ub300\ub2f5\uc740 \uc6b0\uc120 click_action\uc758 \uac12\uc744 \uc5ec\ub7ec \uac12\uc744 \uc8fc\uc9c0\ub9d0\uace0 \ud558\ub098\uc758 \uac12\uc73c\ub85c \ud1b5\uc77c\ud574\uc57c \ud569\ub2c8\ub2e4.\\n```\\n\\"click_action\\" : \\"KOIN\\"\\n```\\n\ub2e4\uc74c\uacfc \uac19\uc774 \ubaa8\ub4e0 \uc54c\ub9bc\uc758 click_action \uc744 \ud1b5\uc77c\ud569\ub2c8\ub2e4.\\n\\n\uadf8\ub9ac\uace0 \ud558\ub098\uc758 \ud22c\uba85 \uc561\ud2f0\ube44\ud2f0\ub85c \uc774\ub3d9\ud558\uac8c `Manifest.xml` \uc5d0 \uc124\uc815\ud574\uc8fc\uba74 \ub429\ub2c8\ub2e4.\\n\\n:::info\\n\ud22c\uba85 \uc561\ud2f0\ube44\ud2f0\ub294 \ud2b9\uc815 \ud654\uba74\uc758 UI\ub97c \uad00\ub9ac\ud558\uc9c0 \uc54a\uace0, \uc2a4\ud0b4 \ucc98\ub9ac\ub97c \ud558\uae30 \uc704\ud574 \uc544\ubb34\uac83\ub3c4 \ud558\uc9c0 \uc54a\uace0 \ud22c\uba85\ud55c \ud558\ub098\uc758 \uc561\ud2f0\ube44\ud2b8\ub97c \uc758\ubbf8\ud569\ub2c8\ub2e4.\\n:::\\n\\n`Manifest.xml` \uc5d0\ub294 \uc544\ub798 \ucf54\ub4dc\ucc98\ub7fc \uc124\uc815\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n```kotlin\\n<activity\\n    android:name=\\".activity.SchemeActivity\\"\\n    android:exported=\\"false\\"\\n    <intent-filter>\\n        <action android:name=\\"KOIN\\"/>\\n        <category android:name=\\"android.intent.category.DEFAULT\\"/>\\n    </intent-filter>\\n</activity>\\n```\\n\\nSchemeActivity \ub77c\ub294 \ud22c\uba85 \uc561\ud2f0\ube44\ud2f0\ub97c \ub9cc\ub4e4\uace0, data \ud398\uc774\ub85c\ub4dc\uac00 notification \uc774\ub791 \uac19\uc774\uc628\ub2e4\uace0 \uc704\uc5d0\uc11c \uc608\uc2dc\ub97c \ubcf4\uc5ec\uc8fc\uc5c8\uc2b5\ub2c8\ub2e4. \uc5ec\uae30\uc11c data \ud398\uc774\ub85c\ub4dc\ub97c \uc0ac\uc6a9\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.  \\n\uadf8\ub807\ub2e4\ub294\uac83\uc740 \ud574\ub2f9 \uc561\ud2f0\ube44\ud2f0\uc5d0\uc11c \uace0\uae43\uc9d1 \uc0c1\uc810 \ud504\ub798\uadf8\uba3c\ud2b8\ub85c \uc0c1\uc138 \uc774\ub3d9\ud574\uc57c\ud55c\ub2e4\uba74, \uc0c1\uc810 \uc561\ud2f0\ube44\ud2f0\ub85c \uc774\ub3d9\ud560 \ub54c intent \ub85c \uac12\uc744 \uc804\ub2ec\ud574\uc8fc\uace0 \ud574\ub2f9 \uc561\ud2f0\ube44\ud2f0\uc5d0\uc11c \uace0\uae43\uc9d1 \uc0c1\uc810 \ud504\ub798\uadf8\uba3c\ud2b8\ub85c \uc774\ub3d9\ud558\uba74 \ub429\ub2c8\ub2e4.\\n\\ndata \ud398\uc774\ub85c\ub4dc\ub294 \ub2e4\uc74c\uacfc \uac19\uc774 \uc628\ub2e4\uace0 \uac00\uc815\ud558\uaca0\uc2b5\ub2c8\ub2e4.\\n```kotlin\\n\\"data\\" : {\\n  \\"title\\" : \\"\uc81c\ubaa9\\",\\n  \\"url\\" : \\"koin://shop?id=1\\"\\n}\\n```\\n\\n\uc561\ud2f0\ube44\ud2f0\uc5d0\uc11c intent \ub85c \ud655\uc778 \uac00\ub2a5\ud569\ub2c8\ub2e4.\\n\\n\\n```kotlin\\noverride fun onCreate(savedInstanceState: Bundle?) {\\n    super.onCreate(savedInstanceState)\\n    setContentView(binding.root)\\n\\n    Log.e(\\"aaa\\", \\"${intent.data}\\")\\n    Log.e(\\"aaa\\", \\"${intent.extras}\\")\\n    for (key in intent.extras?.keySet()!!) {\\n        val value: Any? = intent.extras?.get(key)\\n\\n        Log.e(\\"aaa\\", \\"key / value : ${key} / ${value}\\")\\n    }\\n}\\n```\\n\\n\uc704 \ub85c\uadf8\uc5d0 \ub300\ud55c \ucd9c\ub825\uc740 \uc544\ub798\uc640 \uac19\uc2b5\ub2c8\ub2e4.\\n```kotlin\\n>>>\\nkey / value : google.delivered_priority / normal\\nkey / value : google.sent_time / 1724374925420\\nkey / value : google.ttl / 2419200\\nkey / value : google.original_priority / normal\\nkey / value : data_type / type\\nkey / value : google.product_id / 111881503\\nkey / value : from / 340135824028\\nkey / value : google.message_id / 0:1724374925428874%0988106009881060\\nkey / value : gcm.n.analytics_data / Bundle[mParcelledData.dataSize=100]\\nkey / value : data_title / title\\nkey / value : collapse_key / in.koreatech.koin\\n```\\n\uc704\uc640 \uac19\uc774 getIntet \ub85c \ub370\uc774\ud130\ub97c key, value \ud615\uc2dd\uc73c\ub85c \ubc1b\uc544\ubcfc \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\\n\uc704 \ucf54\ub4dc\ub97c \uc0ac\uc6a9\ud55c\ub2e4\uba74? \uc6b0\ub9ac\ub294 notification \ud398\uc774\ub85c\ub4dc\ub97c \uc804\ub2ec\ubc1b\uc740 FCM \ubc29\uc2dd\uc5d0\uc11c\ub3c4 \uc0c1\uc138 \ud654\uba74\uc73c\ub85c \uc774\ub3d9\ud560 \uc218 \uc788\uac8c \ub418\uc5c8\ub2f5\ub2c8\ub2e4!"},{"id":"/jokwanhee/jkh_gradle_cleanup","metadata":{"permalink":"/android/jokwanhee/jkh_gradle_cleanup","source":"@site/@android/jokwanhee/jkh_gradle_cleanup.mdx","title":"\ucf54\uc778 Gradle \uccad\uc18c \ud6c4\uae30","description":"Gradle \uc5b8\uc5b4\ub97c Groovy \uc5d0\uc11c Kotlin DSL\ub85c \ubcc0\uacbd\ud558\uace0, \uc774\uac83\uc800\uac83 \uccad\uc18c\ub97c \ud574\ubd24\uc2b5\ub2c8\ub2e4.","date":"2024-07-08T00:00:00.000Z","tags":[{"label":"\uc548\ub4dc\ub85c\uc774\ub4dc","permalink":"/android/tags/\uc548\ub4dc\ub85c\uc774\ub4dc"},{"label":"Gradle","permalink":"/android/tags/gradle"}],"readingTime":7.435,"hasTruncateMarker":true,"authors":[{"name":"JoKwanhee","url":"https://github.com/Jokwanhee","email":"jonotch1@naver.com","imageURL":"https://avatars.githubusercontent.com/u/90740783?v=4","key":"jokwanhee"}],"frontMatter":{"date":"2024-07-08T00:00:00.000Z","authors":"jokwanhee","title":"\ucf54\uc778 Gradle \uccad\uc18c \ud6c4\uae30","description":"Gradle \uc5b8\uc5b4\ub97c Groovy \uc5d0\uc11c Kotlin DSL\ub85c \ubcc0\uacbd\ud558\uace0, \uc774\uac83\uc800\uac83 \uccad\uc18c\ub97c \ud574\ubd24\uc2b5\ub2c8\ub2e4.","keywords":["\uc548\ub4dc\ub85c\uc774\ub4dc","Gradle"],"tags":["\uc548\ub4dc\ub85c\uc774\ub4dc","Gradle"]},"unlisted":false,"prevItem":{"title":"[FCM] Remote Notification Message","permalink":"/android/jokwanhee/jkh_fcm_notification_message"},"nextItem":{"title":"\uc548\ub4dc\ub85c\uc774\ub4dc \uc2a4\ud130\ub514 Fork \ubc29\ubc95","permalink":"/android/jokwanhee/jkh_study_fork"}},"content":"Gradle \uc5b8\uc5b4\ub97c Groovy \uc5d0\uc11c Kotlin DSL\ub85c \ubcc0\uacbd\ud558\uace0, \uc774\uac83\uc800\uac83 \uccad\uc18c\ub97c \ud574\ubd24\uc2b5\ub2c8\ub2e4.\\n\\n\ucf54\ub4dc \uba3c\uc800 \ud655\uc778\ud574\ubcf4\ub824\uba74 \ud574\ub2f9 [PR](https://github.com/BCSDLab/KOIN_ANDROID/pull/302)\uc744 \ud655\uc778\ud574\uc8fc\uc138\uc694!\\n\\n{/* truncate */}\\n\\n## Groovy \uc5d0\uc11c Kotlin DSL \uc801\uc6a9 \uc2dc \uace0\ub824\ud560 \uc810\\n\uae30\ubcf8\uc801\uc73c\ub85c Groovy \uc5b8\uc5b4\ub85c \ub418\uc5b4\uc788\ub294 gradle \ud30c\uc77c\uc744 Kotlin DSL \ub85c \ub9c8\uc774\uadf8\ub808\uc774\uc158 \ud560 \ub54c \uc8fc\uc758\ud560 \uc810\uc774 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\uc790\uc138\ud55c \ub0b4\uc6a9\uc744 \ubcf4\uace0\uc2f6\uc73c\uba74, [\uacf5\uc2dd\ubb38\uc11c](https://developer.android.com/build/migrate-to-kotlin-dsl)\ub97c \ucc38\uace0\ud574\uc8fc\uc138\uc694.\\n\\n\ub9c8\uc774\uadf8\ub808\uc774\uc158 \ub4e4\uc5b4\uac00\uae30 \uc55e\uc11c \uc8fc\uc758\ud560 \uc810\uc740 build.gradle \ud30c\uc77c \u2192 build.gradle.kts \ub85c \ud30c\uc77c\uba85\uc744 \ubcc0\uacbd\ud560 \ub54c, kts \ud30c\uc77c\uc5d0\uc11c groovy \uc5b8\uc5b4\ub97c \uc778\uc2dd\ud558\uc9c0 \ubabb\ud558\uae30 \ub54c\ubb38\uc5d0\\n\uae30\uc874 build.gradle \ud30c\uc77c\uc5d0\uc11c \uc5b4\ub290\uc815\ub3c4 \ub9c8\uc774\uadf8\ub808\uc774\uc158\uc744 \uc9c4\ud589\ud55c \ub4a4, kts \ud655\uc7a5\uc790 \ud30c\uc77c\ub85c \ubcc0\uacbd\ud574\uc8fc\uc2dc\uba74 \uc2a4\ud2b8\ub808\uc2a4\ub97c \ub35c \ubc1b\uc2b5\ub2c8\ub2e4.\\n\\n- groovy \uc5b8\uc5b4\ub294 \uba54\uc11c\ub4dc \ud638\ucd9c \uc2dc \uad04\ud638\ub97c \uc0dd\ub7b5\ud558\uc9c0\ub9cc, kotlin dsl \uc5d0\uc11c\ub294 \uad04\ud638\uac00 \ud544\uc694\ud569\ub2c8\ub2e4.\\n```kotlin\\ncompileSdkVersion 30 // Groovy\\ncompileSdkVersion(30) // Kotlin DSL\\n```\\n\\n- groovy \uc5b8\uc5b4\uc5d0\uc11c\ub294 \uc18d\uc131 \ud560\ub2f9 \uc2dc = \uc5f0\uc0b0\uc790\uac00 \ud544\uc694\uc5c6\uc9c0\ub9cc, kotlin dsl \ub294 \ud544\uc694\ud558\ub2e4.\\n```kotlin\\nsourceCompatibility JavaVersion.VERSION_17 // Groovy\\nsourceCompatibility = JavaVersion.VERSION_17 // Kotlin DSL\\n```\\n\\n- groovy \uc5b8\uc5b4\uc5d0\uc11c\ub294 \uc791\uc740 \ub530\uc634\ud45c\ub97c \uc0ac\uc6a9\ud558\uace0, kotlin dsl \uc5d0\uc11c\ub294 \ud070 \ub530\uc634\ud45c\ub97c \uc0ac\uc6a9\ud55c\ub2e4.\\n```kotlin\\nid \'com.android.application\' // Groovy\\nid (\\"com.android.application\\") // Kotlin DSL\\n```\\n\\n- \ubcc0\uc218 \uc815\uc758 \ubc29\ubc95\\n```kotlin\\ndef building64Bit = false // Groovy\\nval building64Bit = false // Kotlin DSL\\n```\\n\\n- \ubd80\uc6b8 \uc18d\uc131\uc758 \uc811\ub450\uc0ac\\n```kotlin\\nminifyEnabled true // Groovy\\nisMinifyEnabled = true // Kotlin DSL\\n```\\n\\n- \ub9ac\uc2a4\ud2b8 \ubc0f \ub9f5 \ud615\uc2dd\\n```kotlin\\njvmOptions += [\\"-Xms4000m\\", \\"-Xmx4000m\\", \\"-XX:+HeapDumpOnOutOfMemoryError</code>\\"] // Groovy\\njvmOptions += listOf(\\"-Xms4000m\\", \\"-Xmx4000m\\", \\"-XX:+HeapDumpOnOutOfMemoryError\\") // Kotlin DSL\\n```\\n```kotlin\\ndef myMap = [key1: \'value1\', key2: \'value2\'] // Groovy\\nval myMap = mapOf(\\"key1\\" to \\"value1\\", \\"key2\\" to \\"value2\\") // Kotlin DSL\\n```\\n\\n## \ub9c8\uc774\uadf8\ub808\uc774\uc158\ud558\uba74\uc11c \uc9c4\ud589\ub41c \ucf54\ub4dc \uc815\ub9ac\\n\ub9c8\uc774\uadf8\ub808\uc774\uc158\uc744 \uc9c4\ud589\ud558\uba74\uc11c \ud754\ud558\uac8c \uc0ac\uc6a9\ub418\ub294 build.gradle \uc740 groovy \uc5d0\uc11c Kotlin DSL \ub85c \uc5b4\ub5bb\uac8c \ubcc0\ud654\ub418\uc5c8\ub294 \uc9c0 \uc804\uccb4\uc801\uc778 \ucf54\ub4dc\ub97c \ube44\uad50\ud558\uc5ec \uc815\ub9ac\ud558\ub824\uace0 \ud569\ub2c8\ub2e4.\\n\ucd94\uac00\uc801\uc73c\ub85c, \ucf54\uc778 \uc11c\ube44\uc2a4\uc5d0\uc11c\ub294 version catalog \uac00 \uc0ac\uc6a9\ub418\uc5c8\uc73c\uba70, convention plugin \uc5b4\ub5a4 \uac83\uc744 \ucd94\uac00\ud588\ub294 \uc9c0 \uc815\ub9ac\ud574\ubcf4\uaca0\uc2b5\ub2c8\ub2e4.\\n\ucf54\ub4dc\uc758 \uc21c\uc11c\ub294 Groovy, Kotlin DSL \uc21c\uc11c\uc785\ub2c8\ub2e4.\\n### build.gradle(project)\\n- Groovy\\n```kotlin Groovy\\nbuildscript {\\n    repositories {\\n        google()\\n        mavenCentral()\\n    }\\n\\n    ext {\\n        /* Common */\\n        compileSdkVersion = 34\\n        minSdkVersion = 21\\n        targetSdkVersion = 34\\n        versionName = \\"3.4.3\\"\\n        minVersionCode = 30403\\n    }\\n\\n    dependencies {\\n        classpath libs.android.gradle.tool\\n        classpath libs.kotlin.gradle\\n        classpath libs.android.gradle.crashlytics\\n        classpath libs.firebase.appdistribution.gradle\\n        classpath libs.hilt.gradle.plugin\\n    }\\n}\\n\\nplugins {\\n    alias(libs.plugins.android.application) apply false\\n    alias(libs.plugins.kotlin.android) apply false\\n    alias(libs.plugins.hilt) apply false\\n    alias(libs.plugins.kotlin.jvm) apply false\\n    alias(libs.plugins.google.service) apply false\\n    alias(libs.plugins.androidLibrary) apply false\\n}\\n\\ntasks.register(\'clean\', Delete) {\\n    delete rootProject.buildDir\\n}\\n\\n```\\n- Kotlin DSL\\n```kotlin\\nbuildscript {\\n    repositories {\\n        google()\\n        mavenCentral()\\n    }\\n\\n    extra.apply {\\n        set(\\"compileSdkVersion\\", 34)\\n        set(\\"minSdkVersion\\", 24)\\n        set(\\"targetSdkVersion\\", 34)\\n        set(\\"versionName\\", \\"3.4.3\\")\\n        set(\\"versionCode\\", 30403)\\n    }\\n\\n    dependencies {\\n        classpath(libs.android.gradle.tool)\\n        classpath(libs.kotlin.gradle)\\n        classpath(libs.android.gradle.crashlytics)\\n        classpath(libs.firebase.appdistribution.gradle)\\n        classpath(libs.hilt.gradle.plugin)\\n    }\\n}\\n\\nplugins {\\n    alias(libs.plugins.android.application) apply false\\n    alias(libs.plugins.kotlin.android) apply false\\n    alias(libs.plugins.hilt) apply false\\n    alias(libs.plugins.kotlin.jvm) apply false\\n    alias(libs.plugins.google.service) apply false\\n    alias(libs.plugins.androidLibrary) apply false\\n}\\n\\ntasks.register<Delete>(\\"clean\\") {\\n    delete(rootProject.buildDir)\\n}\\n```\\n\\n### build.gradle \ud50c\ub7ec\uadf8\uc778 id \ucd94\uac00\ud558\ub294 \ubc29\ubc95\\n```kotlin\\n// groovy\\nplugins {\\n    id \'com.android.application\'\\n}\\n\\n// Kotlin DSL\\nplugins {\\n    id (\\"com.android.application\\")\\n}\\n```\\n\\n### naverMapKey local.properites \ud30c\uc77c\uc5d0\uc11c \ud0a4 \uac12 \uac00\uc838\uc640 manifest \uc5d0 \ub4f1\ub85d\ud558\uae30\\n- Groovy\\n```kotlin\\nandroid {\\n    defaultConfig {\\n        manifestPlaceholders = [naverMapKey: getNaverMapKey()]\\n    }\\n}\\n\\ndef getNaverMapKey() {\\n    Properties properties = new Properties()\\n    properties.load(project.rootProject.file(\'local.properties\').newDataInputStream())\\n    return properties.getProperty(\'navermap_key\')\\n}\\n```\\n\\n- Kotlin DSL\\n```kotlin\\nimport com.android.build.gradle.internal.cxx.configure.gradleLocalProperties\\n\\nandroid {\\n    defaultConfig {\\n        manifestPlaceholders[\\"naverMapKey\\"] = getPropertyKey(\\"navermap_key\\")\\n    }\\n}\\n\\nfun getPropertyKey(propertyKey: String): String {\\n    val nullableProperty: String? =\\n        gradleLocalProperties(rootDir).getProperty(propertyKey)\\n    return nullableProperty ?: \\"null\\"\\n}\\n```\\n\\nlocal.properties \uc5d0\ub294 \ub2e4\uc74c\uacfc \uac19\uc774 navermap key \uac00 \uc120\uc5b8\ub418\uc5b4 \uc788\uc744\uac81\ub2c8\ub2e4.\\n```kotlin\\nnavermap_key=******* // \uc30d\ub530\uc74c\ud45c \uc5c6\uc774\\n```\\n\\n\ub2e4\uc74c Manifest \uc5d0\ub3c4 \ub2e4\uc74c\uacfc \uac19\uc774 \uba54\ud0c0\ub370\uc774\ud130\ub85c navermap key \ub97c \ud560\ub2f9\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n```kotlin\\n<meta-data\\n  android:name=\\"com.naver.maps.map.CLIENT_ID\\"\\n  android:value=\\"${naverMapKey}\\"/>\\n```\\n\\n### \uc11c\uba85 \uc124\uc815\ud558\ub294 \ubc29\ubc95\\n\ud574\ub2f9 \uad00\ub828 Kotlin DSL \ucf54\ub4dc\ub97c \uc790\uc138\ud788 \ubcf4\uae30 \uc704\ud574\uc11c\ub294 [\ubb38\uc11c](https://gist.github.com/mileskrell/7074c10cb3298a2c9d75e733be7061c2)\ub97c \ucc38\uace0\ud574\uc8fc\uc138\uc694.\\n- Groovy\\n```kotlin\\nandroid {\\nsigningConfigs {\\n    release {\\n        storeFile file(\\"./team_kap_android.jks\\")\\n        storePassword = getPassword()\\n        keyAlias = \\"koin_release_key\\"\\n        keyPassword = getPassword()\\n    }\\n}\\n}\\n\\nfun getPassword() {\\n  val properties = new Properties()\\n  properties.load(project.rootProject.file(\'local.properties\').newDataInputStream())\\n  return properties.getProperty(\'koin_store_password\')\\n}\\n```\\n\\n- Kotlin DSL\\n```kotlin\\nimport com.android.build.gradle.internal.cxx.configure.gradleLocalProperties\\n\\nandroid {\\n    signingConfigs {\\n        create(\\"release\\") {\\n            storeFile = file(\\"./team_kap_android.jks\\")\\n            storePassword = getPropertyKey(\\"koin_store_password\\")\\n            keyAlias = getPropertyKey(\\"koin_release_key\\")\\n            keyPassword = getPropertyKey(\\"koin_store_password\\")\\n        }   \\n    }\\n}\\n\\nfun getPropertyKey(propertyKey: String): String {\\n  val nullableProperty: String? =\\n      gradleLocalProperties(rootDir).getProperty(propertyKey)\\n  return nullableProperty ?: \\"null\\"\\n}\\n```\\n\\n### \ube4c\ub4dc \ud0c0\uc785 \uad6c\ubd84, \ub514\ubc84\uadf8 & \ub9b4\ub9ac\uc988\\n- Groovy\\n```kotlin\\nandroid {\\n    buildTypes {\\n        debug {\\n            debuggable true\\n            minifyEnabled true\\n            proguardFiles getDefaultProguardFile(\'proguard-android.txt\'), \'proguard-rules.pro\'\\n            buildConfigField \\"boolean\\", \\"IS_DEBUG\\", \\"true\\"\\n            firebaseCrashlytics {\\n                mappingFileUploadEnabled false\\n            }\\n        }\\n            \\n        release {\\n            minifyEnabled true\\n            proguardFiles getDefaultProguardFile(\'proguard-android.txt\'), \'proguard-rules.pro\'\\n            buildConfigField \\"boolean\\", \\"IS_DEBUG\\", \\"false\\"\\n            signingConfig = signingConfigs.release\\n            firebaseAppDistribution {\\n                artifactType = \\"AAB\\"\\n                releaseNotes = \\"${project.versionName} release\\"\\n                groups = \\"bcsd\\"\\n            }\\n        }\\n    }\\n}\\n```\\n\\n- Kotlin DSL\\n```kotlin\\nandroid {\\n  buildTypes {\\n    getByName(\\"debug\\") {\\n      isDebuggable = true\\n      isMinifyEnabled = false\\n      proguardFiles(\\n          getDefaultProguardFile(\\"proguard-android-optimize.txt\\"), \\"proguard-rules.pro\\"\\n      )\\n      buildConfigField(\\"Boolean\\", \\"IS_DEBUG\\", \\"true\\")\\n      firebaseCrashlytics {\\n          mappingFileUploadEnabled = false\\n      }\\n    }\\n\\n    getByName(\\"release\\") {\\n      isMinifyEnabled = true\\n      proguardFiles(\\n          getDefaultProguardFile(\\"proguard-android-optimize.txt\\"), \\"proguard-rules.pro\\"\\n      )\\n      buildConfigField(\\"Boolean\\", \\"IS_DEBUG\\", \\"false\\")\\n      signingConfig = signingConfigs.getByName(\\"release\\")\\n      firebaseAppDistribution {\\n          artifactType = \\"AAB\\"\\n          releaseNotes = \\"${rootProject.extra[\\"versionName\\"]} release\\"\\n          groups = \\"bcsd\\"\\n      }\\n    }\\n  }\\n}\\n```\\n\\n### Convention Plugin, Application \uacfc Library Extension \uad6c\ubd84\ud558\uae30\\nConvention Plugin extension \uc744 \ub2e4\uc74c\uacfc \uac19\uc774 \uc9c4\ud589\ud560 \ub54c, library \ubaa8\ub4c8\uc5d0\uc11c\ub294 LibraryExtension \uc744 \uc0ac\uc6a9\ud558\uace0, application \ubaa8\ub4c8\uc5d0\uc11c\ub294 ApplicationExtension \uc744 \uc0ac\uc6a9\ud558\uc5ec \ud63c\ub3d9\ud574\uc11c \uc0ac\uc6a9\ud558\uc9c0 \ub9d0\uc544\uc57c \ud569\ub2c8\ub2e4.\\n\uae30\uc874 \ucf54\uc778 \uc11c\ube44\uc2a4\uc5d0\uc11c Hilt ConventionPlugin \uc744 ApplicationExtension \uc744 \uc0ac\uc6a9\ud558\uc5ec \uc758\uc874\uc131\uc744 \uc8fc\uc785\ud558\uace0 \uc788\uc5b4 library \ubaa8\ub4c8\uc778 data, core \ubaa8\ub4c8\uc5d0\uc11c \uc0ac\uc6a9\ud558\uc9c0 \ubabb\ud55c \uacbd\ud5d8\uc774 \uc788\uc2b5\ub2c8\ub2e4.\\n```kotlin\\napply(\\"com.android.library\\")\\n\\nextensions.configure<LibraryExtension> {\\n    configureAndroidLibrary(this)\\n}\\n```\\n\\n```kotlin\\napply(\\"com.android.application\\")\\n\\nextensions.configure<ApplicationExtension> {\\n  configureAndroidProject(extension)\\n} \\n```\\n\\n\ucd94\uac00\uc801\uc73c\ub85c, ConventionPlugin \uc744 \uc9c4\ud589\ud558\uba74\uc11c FirebaseConventionPlugin, JavaLibraryConventionPlugin \uc744 \ucd94\uac00\ud574\ubcf4\uc558\uc2b5\ub2c8\ub2e4.\\n\\n## \uc18c\uac10\\nGroovy \uc5d0\uc11c Kotlin DSL \ub85c \ub9c8\uc774\uadf8\ub9ac\uc774\uc158 \ud558\uba74\uc11c \uae30\uc874\uc5d0 \ud504\ub85c\uc81d\ud2b8\ub97c \ud558\uba74\uc11c Groovy \uc5d0\uc11c\uc758 \uc624\ub958 \ucd94\uc801\uc774 \uc5b4\ub824\uc6b4 \uac83\uc744 Kotlin DSL \ub85c \ud55c\ud3b8 \uc26c\uc6cc\uc84c\uc744 \uac70\ub77c \uae30\ub300\ud569\ub2c8\ub2e4.\\n\ucf54\uc778\uc758 \ubaa8\ub4e0 \ubaa8\ub4c8\uc758 gradle \uc744 \uc0b4\ud53c\uace0 \uc815\ub9ac\ud574\ubcf4\uba74\uc11c, core\uc640 feature \ub2e8\uc704 \ubcc4 \ubaa8\ub4c8\ud654\uc758 \ud544\uc694\uc131\uc744 \ub290\uaf08\uc2b5\ub2c8\ub2e4.\\n\ud63c\uc790 \ud504\ub85c\uc81d\ud2b8\ub97c \ud558\ub294 \uac83\uc774 \uc544\ub2cc \ub2e4\uc591\ud55c \uc0ac\ub78c\ub4e4\uc774 \uac19\uc774 \ud611\uc5c5\ud558\ub2e4\ubcf4\ub2c8 \uac01\uc790\uac00 \uc9c4\ud589\ud558\ub294 feature \ub2e8\uc704 \ubaa8\ub4c8\uc5d0\uc11c \uc9c4\ud589\ud558\uba74 gradle \ub3c4 \ud6e8\uc52c \uae54\ub054\ud574\uc9c8 \uac83 \uac19\uc2b5\ub2c8\ub2e4.\\ncore \ub294 \ub2e8\uc77c\ubaa8\ub4c8\ub85c \uc788\ub294\ub370, \ud574\ub2f9 \ubaa8\ub4c8\uc5d0\uc11c\ub3c4 \ub2e4\uc591\ud55c \ub77c\uc774\ube0c\ub7ec\ub9ac\uac00 \uc788\uc5b4 analytics, notification, designsystem \ub4f1 \ubaa8\ub4c8\ud654\uc758 \ud544\uc694\uc131\uc744 \ub290\uaf08\uc2b5\ub2c8\ub2e4.\\n\uac04\ub2e8\ud788 \uc9c4\ud589\ub420 \uc904 \uc54c\uc558\ub358 \ud574\ub2f9 \uc791\uc5c5\uc740 \uc800\uc5d0\uac8c \ubaa8\ub4c8\ud654\uc758 \uc911\uc694\uc131\uc744 \uae68\ub2eb\uac8c \ud574\uc8fc\uc5c8\uc2b5\ub2c8\ub2e4."},{"id":"/jokwanhee/jkh_study_fork","metadata":{"permalink":"/android/jokwanhee/jkh_study_fork","source":"@site/@android/jokwanhee/jkh_study_fork.mdx","title":"\uc548\ub4dc\ub85c\uc774\ub4dc \uc2a4\ud130\ub514 Fork \ubc29\ubc95","description":"\ucc98\uc74c\uc73c\ub85c \uc2dc\ub3c4\ud558\ub294 \uc548\ub4dc\ub85c\uc774\ub4dc \uc2a4\ud130\ub514\uc758 Fork \ubc29\ubc95\uc744 \ub2e4\ub8f9\ub2c8\ub2e4.","date":"2024-05-03T00:00:00.000Z","tags":[{"label":"\uc548\ub4dc\ub85c\uc774\ub4dc","permalink":"/android/tags/\uc548\ub4dc\ub85c\uc774\ub4dc"},{"label":"\uc2a4\ud130\ub514","permalink":"/android/tags/\uc2a4\ud130\ub514"}],"readingTime":5.24,"hasTruncateMarker":true,"authors":[{"name":"JoKwanhee","url":"https://github.com/Jokwanhee","email":"jonotch1@naver.com","imageURL":"https://avatars.githubusercontent.com/u/90740783?v=4","key":"jokwanhee"}],"frontMatter":{"date":"2024-05-03T00:00:00.000Z","authors":"jokwanhee","title":"\uc548\ub4dc\ub85c\uc774\ub4dc \uc2a4\ud130\ub514 Fork \ubc29\ubc95","description":"\ucc98\uc74c\uc73c\ub85c \uc2dc\ub3c4\ud558\ub294 \uc548\ub4dc\ub85c\uc774\ub4dc \uc2a4\ud130\ub514\uc758 Fork \ubc29\ubc95\uc744 \ub2e4\ub8f9\ub2c8\ub2e4.","keywords":["\uc548\ub4dc\ub85c\uc774\ub4dc","\uc2a4\ud130\ub514"],"tags":["\uc548\ub4dc\ub85c\uc774\ub4dc","\uc2a4\ud130\ub514"]},"unlisted":false,"prevItem":{"title":"\ucf54\uc778 Gradle \uccad\uc18c \ud6c4\uae30","permalink":"/android/jokwanhee/jkh_gradle_cleanup"},"nextItem":{"title":"\uc548\ub4dc\ub85c\uc774\ub4dc \uac1c\ubc1c\uc790\uac00 \ubc14\ub77c\ubcf8 FCM \ud14c\uc2a4\ud2b8","permalink":"/android/jokwanhee/jkh_fcm"}},"content":"\ucc98\uc74c\uc73c\ub85c \uc2dc\ub3c4\ud558\ub294 \uc548\ub4dc\ub85c\uc774\ub4dc \uc2a4\ud130\ub514\uc758 Fork \ubc29\ubc95\uc744 \ub2e4\ub8f9\ub2c8\ub2e4.\\n\\n{/* truncate */}\\n\\n# \uc548\ub4dc\ub85c\uc774\ub4dc \uc2a4\ud130\ub514 Fork \ubc29\ubc95\\n\\n### 1. \uc2a4\ud130\ub514\ub97c \uc9c4\ud589\ud558\ub294 \ub808\ud3ec\uc9c0\ud1a0\ub9ac Fork \ud558\uae30\\n\\n\ud604\uc7ac \uc9c4\ud589\ub418\ub294 \uc2a4\ud130\ub514 \ub808\ud3ec\uc9c0\ud1a0\ub9ac\uc758 \uacbd\ub85c\ub294 BCSD_Android_Study \uc624\uac00\ub2c8\uc81c\uc774\uc158\uc758 study-android \ub808\ud3ec\uc9c0\ud1a0\ub9ac\ub97c \uc544\ub798\uc758 \uc0ac\uc9c4\ucc98\ub7fc Fork \ud558\uba74 \ub429\ub2c8\ub2e4.\\n\\n<img src=\\"/img/@android/jkh_study_fork/study_fork1.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"0px\\" }} />\\n\\n### 2. \ub098\uc758 \ub808\ud3ec\uc9c0\ud1a0\ub9ac\uc758 Fork \ub418\uc5c8\ub294\uc9c0 \ud655\uc778\\n\\nFork \uc774\ud6c4, \ub098\uc758 \ub808\ud3ec\uc9c0\ud1a0\ub9ac\uc758 Fork \ud55c \ub808\ud3ec\uc9c0\ud1a0\ub9ac\uac00 \uc798 \ub4e4\uc5b4\uc654\ub294 \uc9c0 \ud655\uc778\ud569\ub2c8\ub2e4.\\n<img src=\\"/img/@android/jkh_study_fork/study_fork2.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"0px\\" }} />\\n\\n### 3. Fork \ub41c \ub808\ud3ec\uc9c0\ud1a0\ub9ac \uc7ac\ud655\uc778\\n\\n\ub808\ud3ec\uc9c0\ud1a0\ub9ac\ub85c \ub4e4\uc5b4\uc640\uc11c Forked from BCSD-Android-Study/study-android \ub418\uc5c8\ub294 \uc9c0 \uc7ac\ud655\uc778\ud569\ub2c8\ub2e4.\\n\\n<img src=\\"/img/@android/jkh_study_fork/study_fork3.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"0px\\" }} />\\n\\n### 4. \ub808\ud3ec\uc9c0\ud1a0\ub9ac Clone\ud558\uae30\\n\\n> **\uc800\ub294 git bash\ub97c \ud1b5\ud574\uc11c git \uc791\uc5c5\uc744 \uc9c4\ud589\ud558\uaca0\uc2b5\ub2c8\ub2e4. (GUI \uc4f0\uc2dc\ub294 \ubd84\ub4e4\uc740 \uc798 \ud558\uc2e4\uac70\ub77c \ubbff\uc2b5\ub2c8\ub2e4!)**\\n> \\n\\nFork\ub41c \ub808\ud3ec\uc9c0\ud1a0\ub9ac\ub97c \ub2e4\uc74c\uacfc \uac19\uc774 clone\ud558\uc5ec \ub0b4 \ub85c\uceec\ub85c \uac00\uc838\uc635\ub2c8\ub2e4.\\n\\n<img src=\\"/img/@android/jkh_study_fork/study_fork4.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"0px\\" }} />\\n\\n### 5. Clone \ud30c\uc77c \ud655\uc778\ud558\uae30\\n\\nClone \ud55c \ud30c\uc77c\uc774 \ub85c\uceec\uc5d0 \uc798 \ub4e4\uc5b4\uc654\ub294 \uc9c0 \ud655\uc778\ud569\ub2c8\ub2e4.\\n\\n<img src=\\"/img/@android/jkh_study_fork/study_fork5.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"0px\\" }} />\\n\\n### 6. Commit \ubc0f Push \ud558\uae30\\n\\n\ud604\uc7ac Unstaged \ub418\uc5c8\ub294 \uc9c0 \ud655\uc778\ud558\uae30 \uc704\ud574\uc11c `git status` \uba85\ub839\uc5b4\ub85c \ube68\uac04 \uc0c1\ud0dc(Unstaged) \ud655\uc778\uc744 \ud569\ub2c8\ub2e4. \ud655\uc778\ud55c \ub4a4, \ud574\ub2f9 Unstaged \uc0c1\ud0dc\ub97c Staged \uc0c1\ud0dc\ub85c \ubc14\uafb8\uae30 \uc704\ud574 `git add .` \uba85\ub839\uc5b4\ub97c \uc785\ub825\ud569\ub2c8\ub2e4.\\n\\n<img src=\\"/img/@android/jkh_study_fork/study_fork6.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"0px\\" }} />\\n\\n\uadf8 \ub2e4\uc74c\uc73c\ub85c \ud574\ub2f9 \ud30c\uc77c\uc774 Staged \uc0c1\ud0dc\ub85c \uc798 \ub418\uc5c8\ub294 \uc9c0 \uc7ac\ud655\uc778\ud558\uae30 \uc704\ud574\uc11c `git status` \uba85\ub839\uc5b4\ub85c \uc7ac\ud655\uc778\ud569\ub2c8\ub2e4.\\n\\n<img src=\\"/img/@android/jkh_study_fork/study_fork7.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"0px\\" }} />\\n\\n\\n\uadf8 \ub2e4\uc74c Staged \ub41c \ud30c\uc77c\uc744 \ucee4\ubc0b\ud569\ub2c8\ub2e4. \uc544\ub798\uc758 \uba85\ub839\uc5b4 \ucc98\ub7fc `git commit -m \u201c\uc6d0\ud558\ub294 \uba54\uc2dc\uc9c0\u201d` \uba85\ub839\uc5b4\ub97c \uc785\ub825\ud569\ub2c8\ub2e4. \\n\\n<img src=\\"/img/@android/jkh_study_fork/study_fork8.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"0px\\" }} />\\n\\n\\n\ucee4\ubc0b\uc774 \uc131\uacf5\uc801\uc73c\ub85c \ub418\uc5c8\ub2e4\uba74, \ub85c\uceec\uc758 \uc800\uc7a5\uc18c\uc758 \ud30c\uc77c\uc744 \uc6d0\uaca9 \uc800\uc7a5\uc18c\uc778 Github\ub85c \ud574\ub2f9 \ubcc0\uacbd\ub41c \ub0b4\uc5ed\uc744 \ubcf4\ub0b4\uc8fc\uae30 \uc704\ud574 \ud478\uc26c\ud569\ub2c8\ub2e4. `git push origin main` \uba85\ub839\ub97c \uc0ac\uc6a9\ud569\ub2c8\ub2e4. \\n\\n<img src=\\"/img/@android/jkh_study_fork/study_fork9.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"0px\\" }} />\\n\\n\\n\ub2e4\uc2dc \ud55c \ubc88 push\uac00 \uc798 \ub418\uc5c8\ub294 \uc9c0 \ud655\uc778\ud558\uae30 \uc704\ud574 \ub85c\uadf8\ub97c \ucc0d\uc5b4\ubcf4\uba70 \ub9c8\ubb34\ub9ac\ud569\ub2c8\ub2e4. \\n\\n`git log --oneline`\\n\\n<img src=\\"/img/@android/jkh_study_fork/study_fork10.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"0px\\" }} />\\n\\n\\n### 7. Fork \ub41c \ub808\ud3ec\uc9c0\ud1a0\ub9ac\uc758 Commit \ub0b4\uc5ed \ud655\uc778\ud558\uae30\\n\\nPush\ub97c \uc9c4\ud589\ud588\ub2e4\uba74, Fork \ud55c \ub808\ud3ec\uc9c0\ud1a0\ub9ac\ub85c \ub3cc\uc544\uc640 \ubcc0\uacbd\ub41c \ub0b4\uc5ed\uc774 Github \ub808\ud3ec\uc9c0\ud1a0\ub9ac\uc5d0 \uc798 \ub4e4\uc5b4\uc654\ub294 \uc9c0 \ud655\uc778\ud569\ub2c8\ub2e4.\\n\\n<img src=\\"/img/@android/jkh_study_fork/study_fork11.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"0px\\" }} />\\n\\n\\n### 8. \uae30\uc874 \ub808\ud3ec\uc9c0\ud1a0\ub9ac\uc5d0\uc11c \uc774\uc288 \uc0dd\uc131\ud558\uae30\\n\\nFork \ub41c \ub808\ud3ec\uc9c0\ud1a0\ub9ac\uac00 \uc544\ub2cc Fork\ub97c \uc9c4\ud589\ud588\ub358 \ub808\ud3ec\uc9c0\ud1a0\ub9ac\ub85c \uc635\ub2c8\ub2e4.\\n\\n\uadf8\ub9ac\uace0 \uc544\ub798\uc640 \uac19\uc774 \uc774\uc288 \ud15c\ud50c\ub9bf \ud615\uc2dd\uc5d0 \ub9de\uac8c \uc774\uc288\ub97c \uc0dd\uc131\ud569\ub2c8\ub2e4. (\uc800\ub294 #2 \uc774\uc288\ubc88\ud638\ub97c \ubc1b\uc558\uc2b5\ub2c8\ub2e4.)\\n\\n<img src=\\"/img/@android/jkh_study_fork/study_fork12.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"0px\\" }} />\\n\\n\\n### 9. Fork \ub41c \ub808\ud3ec\uc9c0\ud1a0\ub9ac\uc5d0\uc11c \uae30\uc874 \ub808\ud3ec\uc9c0\ud1a0\ub9ac\ub85c Pull Request \ubcf4\ub0b4\uae30\\n\uc544\ub798\uc758 \uc0ac\uc9c4\ucc98\ub7fc \ucee4\ubc0b\uc744 \ud55c \ub0b4\uc5ed\uc774 \uc788\ub2e4\uba74 Pull Request\ub97c \ubcf4\ub0bc \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n**Jokwanhee/study-android \u2192 BCSD-Android-Study/study-android** \ucc98\ub7fc Pull Request\ub97c \ubcf4\ub0c5\ub2c8\ub2e4.\\n\\nCreate Pull Request\ub97c \ud074\ub9ad\ud574\uc8fc\uc138\uc694.\\n\\n<img src=\\"/img/@android/jkh_study_fork/study_fork13.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"0px\\" }} />\\n\\n\\n### 10. Pull Request \ub9cc\ub4e4\uae30\\n\\n\uc0ac\uc9c4\uacfc \uac19\uc774 \ud480-\ub9ac\ud018\uc2a4\ud2b8 \ud15c\ud50c\ub9bf\uc5d0 \ub9de\uac8c \uc591\uc2dd\uc744 \uc791\uc131\ud55c \ub4a4, \ub9cc\ub4e4\uac8c \ub418\uba74 \uc544\ub798\uc758 \uc0ac\uc9c4\ucc98\ub7fc \ub098\uc635\ub2c8\ub2e4.\\n\\n- **\ub9ac\ubdf0\uc5b4 \ub4f1\ub85d\ud558\uae30**\\n- **\ud560\ub2f9\uc790 \ucd94\uac00\ud558\uae30**\\n- **\ub77c\ubca8 \ub4f1\ub85d\ud558\uae30**\\n\\n\uc774\uc288\ub294 \uc704\uc5d0\uc11c \ub9cc\ub4e0 \uc774\uc288\ubc88\ud638\ub97c \uc0ac\uc6a9\ud558\uc5ec \uc544\ub798\ucc98\ub7fc \uc591\uc2dd\uc5d0 \uc801\uc5b4\uc90d\ub2c8\ub2e4.\\n\\n<img src=\\"/img/@android/jkh_study_fork/study_fork14.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"0px\\" }} />\\n\\n### 11. \uae30\uc874 \ub808\ud3ec\uc9c0\ud1a0\ub9ac\uc5d0\uc11c Pull-Request \ub3c4\ucc29 \uc5ec\ubd80 \ud655\uc778\ud558\uae30\\n\\nPull Request\ub97c \uc9c4\ud589\ud55c \ub4a4, \uae30\uc874 \ub808\ud3ec\uc9c0\ud1a0\ub9ac\uc778 BCSD-Android-Study/study-android \uc5d0 Pull Request\uac00 \ub3c4\ucc29\ud588\ub294 \uc9c0 \ud655\uc778\ud569\ub2c8\ub2e4.\\n\\n<img src=\\"/img/@android/jkh_study_fork/study_fork15.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"0px\\" }} />"},{"id":"/jokwanhee/jkh_fcm","metadata":{"permalink":"/android/jokwanhee/jkh_fcm","source":"@site/@android/jokwanhee/jkh_fcm.mdx","title":"\uc548\ub4dc\ub85c\uc774\ub4dc \uac1c\ubc1c\uc790\uac00 \ubc14\ub77c\ubcf8 FCM \ud14c\uc2a4\ud2b8","description":"\uc124\uba85\uae00 \uc785\ub2c8\ub2e4.","date":"2024-04-07T00:00:00.000Z","tags":[{"label":"\ucf54\ud2c0\ub9b0 \uc2a4\ud504\ub9c1","permalink":"/android/tags/\ucf54\ud2c0\ub9b0-\uc2a4\ud504\ub9c1"},{"label":"Postman","permalink":"/android/tags/postman"},{"label":"FCM","permalink":"/android/tags/fcm"}],"readingTime":20.72,"hasTruncateMarker":true,"authors":[{"name":"JoKwanhee","url":"https://github.com/Jokwanhee","email":"jonotch1@naver.com","imageURL":"https://avatars.githubusercontent.com/u/90740783?v=4","key":"jokwanhee"}],"frontMatter":{"date":"2024-04-07T00:00:00.000Z","authors":"jokwanhee","title":"\uc548\ub4dc\ub85c\uc774\ub4dc \uac1c\ubc1c\uc790\uac00 \ubc14\ub77c\ubcf8 FCM \ud14c\uc2a4\ud2b8","description":"\uc124\uba85\uae00 \uc785\ub2c8\ub2e4.","keywords":["\ud0a4\uc6cc\ub4dc","\uc785\ub825\uc744","\ud569\ub2c8\ub2e4."],"tags":["\ucf54\ud2c0\ub9b0 \uc2a4\ud504\ub9c1","Postman","FCM"]},"unlisted":false,"prevItem":{"title":"\uc548\ub4dc\ub85c\uc774\ub4dc \uc2a4\ud130\ub514 Fork \ubc29\ubc95","permalink":"/android/jokwanhee/jkh_study_fork"}},"content":"Android \uac1c\ubc1c\uc790\uac00 \uac04\ub2e8\ud55c \ub85c\uceec \uc11c\ubc84\ub85c FCM \ud14c\uc2a4\ud2b8\ud574\ubcf4\uae30\uc5d0 \ub300\ud574\uc11c \ub2e4\ub8f9\ub2c8\ub2e4.\\n\\n{/* truncate */}\\n\\n# \ub4e4\uc5b4\uac00\uae30 \uc55e\uc11c\\n\uc774\ubc88\uc5d0 FCM\uc744 \ud14c\uc2a4\ud2b8\ud558\uae30 \uc704\ud574\uc11c \uac04\ub2e8\ud558\uac8c Kotlin-Spring boot\ub97c \uc0ac\uc6a9\ud558\uc5ec \uc11c\ubc84\ub97c \uad6c\ucd95\ud55c \ub4a4, \uc5b4\ub5a4 \ubc29\uc2dd\uc73c\ub85c FCM\uc774 \ub3d9\uc791\ub418\ub294\uc9c0 \ud14c\uc2a4\ud2b8\ud574\ubcf4\uc558\uc2b5\ub2c8\ub2e4.\\n\\n\ud544\uc694\ud55c \uc694\uad6c\uc0ac\ud56d\uc740 \ub2e4\uc74c\uacfc \uac19\uc2b5\ub2c8\ub2e4!\\n- Android Studio\\n- Spring Boot with Kotlin\\n- FCM\\n- Postman\\n\\n# FCM \\n[FCM \uacf5\uc2dd \ubb38\uc11c](https://firebase.google.com/docs/cloud-messaging?authuser=0&hl=ko&_gl=1*o36oja*_up*MQ..*_ga*MTc2MzkxMzYyOS4xNzEyNDc0MDE5*_ga_CW55HF8NVT*MTcxMjQ3NDAxOS4xLjEuMTcxMjQ3NDA4OC4wLjAuMA..)\\n\\n### message format\\nFCM \uc5d0\uc11c \uba54\uc2dc\uc9c0\ub97c \ubcf4\ub0b4\uae30 \uc704\ud55c \uba54\uc2dc\uc9c0 \ud3ec\ub9f7\uc740 \ub2e4\uc74c\uacfc \uac19\uc2b5\ub2c8\ub2e4. \\n- **data**\\n- **notification**\\n- **android**\\n- **webpush**\\n- **apns**\\n- **token**\\n- **topic**\\n- **condition**\\n\\n\uc790\uc138\ud55c \ub0b4\uc6a9\uc740 [\ud30c\uc774\uc5b4\ubca0\uc774\uc2a4 \uacf5\uc2dd \ubb38\uc11c](https://firebase.google.com/docs/reference/fcm/rest/v1/projects.messages?hl=ko)\ub97c \ucc38\uace0\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\\n## Spring Boot with Kotlin\\n:::info \\nSpring Boot\uc5d0 \ub300\ud574\uc11c\ub294 \uc790\uc138\ud788 \ub2e4\ub8e8\uc9c0 \uc54a\uc2b5\ub2c8\ub2e4. \uc544\ub798 \uac15\uc758\ub97c \ub4e3\uace0\uc624\uba74 \ud6e8\uc52c \uc774\ud574\ud558\uae30 \uc27d\uc2b5\ub2c8\ub2e4!\\n\\n\ud559\uc2b5 \uc790\ub8cc : [\uc778\ud504\ub7f0 \uac15\uc758[\ubb34\ub8cc] - \ucf54\ud2c0\ub9b0 \uc2a4\ud504\ub9c1 api\ud638\ucd9c \uc785\ubb38](https://www.inflearn.com/course/lecture?courseSlug=\ucf54\ud2c0\ub9b0-\uc2a4\ud504\ub9c1-api\ud638\ucd9c-\uc785\ubb38&unitId=157832&tab=curriculum)\\n:::\\n\\n\\n### FCM \uae30\ucd08\uc138\ud305\\nFCM \uba54\uc2dc\uc9c0\ub97c \ubcf4\ub0b4\uae30 \uc704\ud55c API\uc758 URL\ub97c \uc0dd\uc131\ud558\ub294\ub370, \uc5ec\uae30\uc11c \uc8fc\uc758\ud574\uc57c\ud560 \uc810\uc740 \ud504\ub85c\uc81d\ud2b8\uc758 \uc774\ub984\uc744 \uc815\ud655\ud558\uac8c \uc801\uc5b4\uc8fc\uc5b4\uc57c \ud569\ub2c8\ub2e4. KOIN \uc5d0\uc11c \uc0ac\uc6a9\ub418\ub294 Firebase \ud504\ub85c\uc81d\ud2b8\ub294 \uc544\ub798\uc640 \uac19\uc774 kap-chat\uc744 \uc0ac\uc6a9\ud569\ub2c8\ub2e4.\\n```kotlin title=\\"FirebaseCloudMessagingService.kt\\"\\nconst val API_URL  = \\"https://fcm.googleapis.com/v1/projects/kap-chat/messages:send\\"\\n```\\n<img src=\\"/img/@android/jkh_fcm/firebase_project_name.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"0px\\" }} />\\n\\n\\n\uadf8 \ub2e4\uc74c\uc73c\ub85c\ub294 Google Cloud \uc758 \uc778\uc99d \uc2dc\uc2a4\ud15c\uc744 \uc704\ud55c \uc561\uc138\uc2a4 \ud1a0\ud070\uc744 \uc5bb\uc5b4\uc57c \ud569\ub2c8\ub2e4.\\nFirebase \uc11c\ube44\uc2a4 \ud0a4 \ud30c\uc77c\uc758 \uacbd\ub85c\ub97c `firebaseConfigPath` \ubcc0\uc218\uc5d0 \uc815\uc758\ud569\ub2c8\ub2e4. (\uc800 \uac19\uc740 \uacbd\uc6b0\uc5d0\ub294 resources/firebase \uacbd\ub85c\uc5d0 \uc800\uc7a5\ud588\uc2b5\ub2c8\ub2e4.)\\n\\n```kotlin title=\\"FirebaseCloudMessagingService.kt\\"\\nprivate fun getAccessToken(): String {\\n    val firebaseConfigPath = \\"firebase/firebase_service_key.json\\"\\n    val credentials = GoogleCredentials\\n        .fromStream(ClassPathResource(firebaseConfigPath).inputStream)\\n        .createScoped(listOf(\\"https://www.googleapis.com/auth/cloud-platform\\"))\\n    credentials.refreshIfExpired()\\n    return credentials.accessToken.tokenValue\\n}\\n```\\n<img src=\\"/img/@android/jkh_fcm/spring_boot_file.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"0px\\" }} />\\n\\n\uc11c\ube44\uc2a4 \ud0a4 \ud30c\uc77c\uc740 \ud504\ub85c\uc81d\ud2b8 \uc124\uc815 / \uc11c\ube44\uc2a4 \uacc4\uc815\uc5d0\uc11c \uc0c8 \ube44\uacf5\uac1c \ud0a4 \uc124\uc815\uc744 \ub204\ub974\uba74 \uc5bb\uc744 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\\n### FCM message\\n\\nFCM\uc744 \uc0ac\uc6a9\ud558\uc5ec \uba54\uc2dc\uc9c0\ub97c \ub9cc\ub4e4\uace0 \ud574\ub2f9 \uba54\uc2dc\uc9c0 \ub9cc\ub4e4\uace0 JSON \ud615\uc2dd\uc758 \ubb38\uc790\uc5f4\ub85c \ubcc0\ud658\ud558\ub294 \uac83\uc774 \ud544\uc694\ud569\ub2c8\ub2e4. \uc774\uc720\ub294 FCM\uc5d0\uac8c RequestBody\ub85c \uc694\uccad\uc744 \ubcf4\ub0b4\uae30 \uc704\ud568\uc785\ub2c8\ub2e4.\\n\\n(*FCM \uba54\uc2dc\uc9c0 \uc815\ubcf4\ub294 [\ud30c\uc774\uc5b4 \uacf5\uc2dd \ubb38\uc11c](https://firebase.google.com/docs/cloud-messaging/concept-options?hl=ko&authuser=0&_gl=1*7wt85m*_up*MQ..*_ga*MTc2MzkxMzYyOS4xNzEyNDc0MDE5*_ga_CW55HF8NVT*MTcxMjQ3NDAxOS4xLjEuMTcxMjQ3NDA4OC4wLjAuMA..&platform=ios)\ub97c \ucc38\uc870\ud574\uc8fc\uc138\uc694)\\n\\nFCM \uba54\uc2dc\uc9c0\uc758 \uae30\ubcf8 \ud3ec\ub9f7\uc740 \ub2e4\uc74c\uacfc \uac19\uc2b5\ub2c8\ub2e4.\\n```json\\n{\\n  \\"message\\":{\\n    \\"token\\":\\"bk3RNwTe3H0:CI2k_HHwgIpoDKCIZvvDMExUdFQ3P1...\\",\\n    \\"notification\\":{\\n      \\"title\\":\\"Portugal vs. Denmark\\",\\n      \\"body\\":\\"great match!\\"\\n    },\\n    \\"data\\" : {\\n      \\"Nick\\" : \\"Mario\\",\\n      \\"Room\\" : \\"PortugalVSDenmark\\"\\n    }\\n  }\\n}\\n```\\n\\n\uc704\uc640 \uac19\uc774 \uba54\uc2dc\uc9c0 \ud3ec\ub9f7\uc744 \uc544\ub798\uc758 data class\ub97c \uc0ac\uc6a9\ud558\uc5ec \ub098\ud0c0\ub0bc \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n```kotlin title=\\"FcmMessage.kt\\"\\ndata class FcmMessage(\\n    val validate_only: Boolean = false,\\n    val message: Message\\n)\\n\\ndata class Message(\\n    val notification: Notification,\\n    val data: Map<String,String>,\\n    val token: String,\\n)\\ndata class Notification(\\n    val title: String,\\n    val body: String,\\n)\\n\\n```\\n\\n\uadf8 \ub2e4\uc74c \uba54\uc2dc\uc9c0\ub97c \ub9cc\ub4e4\uae30 \uc704\ud574\uc11c \uae30\uc874 FCM API\ub97c \uc0ac\uc6a9\ud558\uc9c0 \uc54a\uace0 \uc790\uccb4\uc801\uc778 data class\ub85c \uac04\ub2e8\ud558\uac8c \uc815\uc758\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n```kotlin title=\\"FirebaseCloudMessagingService.kt\\"\\nprivate fun makeMessage(targetToken: String, title: String, body: String): String {\\n    val notification = Notification(title = title, body = body)\\n    val data = mapOf(\\"data_title\\" to \\"title\\", \\"data_type\\" to \\"type\\")\\n    val message = Message(notification = notification, data = data, token = targetToken)\\n    return objectMapper.writeValueAsString(FcmMessage(message = message))\\n}\\n```\\n\\n### FCM \uc694\uccad\ud558\uae30\\n\uc774\uc81c \uae30\ubcf8\uc801\uc778 \uc138\ud305\uc744 \ub05d\ub0b4\uace0 `makeMessage` \ub85c JSON \ubb38\uc790\uc5f4\uc744 \ubc1b\uc544\uc635\ub2c8\ub2e4. \ud574\ub2f9 \ubb38\uc790\uc5f4\uc744 Request Body\uc5d0 \ub2f4\uc544\uc11c FCM \uba54\uc2dc\uc9c0\ub97c \ubcf4\ub0b4\uae30 \uc704\ud55c API Request\ub97c \ub9cc\ub4ed\ub2c8\ub2e4.\\n```kotlin title=\\"FirebaseCloudMessagingService.kt\\"\\n fun sendDirectTo(targetToken: String, title: String, body: String) {\\n    val message = makeMessage(targetToken, title, body)\\n\\n    val client = OkHttpClient()\\n    val requestBody = message\\n        .toRequestBody(\\"application/json; charset=utf-8\\".toMediaType())\\n    val request = Request.Builder()\\n        .url(API_URL)\\n        .post(requestBody)\\n        .addHeader(\\"Authorization\\", \\"Bearer ${getAccessToken()}\\")\\n        .build()\\n    val response = client.newCall(request).execute()\\n}\\n```\\n\\n\ub9cc\ub4e0 API Request\ub294 Controller \ud074\ub798\uc2a4\ub97c \ub9cc\ub4e4\uc5b4\uc11c HTTP POST \uc694\uccad\uc744 \ubcf4\ub0b4\uac8c \ub429\ub2c8\ub2e4.\\n\\n(*\ud574\ub2f9 \uc694\uccad\uc740 Postman\uc744 \uc0ac\uc6a9\ud574\uc11c \ud14c\uc2a4\ud2b8\ud574\ubcfc \uc218 \uc788\uc2b5\ub2c8\ub2e4. \uadf8\uc804\uc5d0 targetToken\uc740 \uc548\ub4dc\ub85c\uc774\ub4dc Device Token\uc744 \uc54c\uc544\uc57c\ud558\uae30 \ub54c\ubb38\uc5d0 \uadf8\uac70 \uba3c\uc800 \uc54c\uc544\ubcf4\uaca0\uc2b5\ub2c8\ub2e4.)\\n```kotlin  title=\\"FcmController.kt\\"\\n@RestController\\nclass FcmController(\\n    private val firebaseCloudMessageService: FirebaseCloudMessageService,\\n) {\\n    @PostMapping(\\"/send\\")\\n    fun send(@RequestBody messageDto: MessageDto): MessageDto {\\n        firebaseCloudMessageService.sendDirectTo(\\n            messageDto.targetToken,\\n            messageDto.title,\\n            messageDto.body\\n        )\\n        return messageDto\\n    }\\n}\\n```\\n\\n\uc774\uc81c\ub294 \uc548\ub4dc\ub85c\uc774\ub4dc\uc5d0\uc11c FCM \uba54\uc2dc\uc9c0\ub97c \uc218\uc2e0\ud558\uace0, Postman \uc5d0\uc11c HTTP POST \uc694\uccad\uc744 \ubcf4\ub0b4\ub294 \ubc29\ubc95\uc5d0 \ub300\ud574\uc11c \uc54c\uc544\ubcf4\uaca0\uc2b5\ub2c8\ub2e4.\\n\\n## Android\\n### FCM \uae30\ucd08\uc138\ud305\\nAndroid \uc5d0\uc11c\ub3c4 FCM \uae30\ucd08\uc138\ud305\uc774 \ud544\uc694\ud569\ub2c8\ub2e4.\\n\\n\uae30\ucd08\uc138\ud305 \uc694\uad6c\uc0ac\ud56d \\n- google-services.json \ud30c\uc77c app \ubaa8\ub4c8\uc5d0 \ub123\uae30\\n- firebase-messaging \uc885\uc18d\uc131 \ucd94\uac00\\n- `FirebaseMessagingService()` \uc0c1\uc18d\ud55c \ud074\ub798\uc2a4 \uc0dd\uc131\\n- manifest service \uad6c\uc131 \ucd94\uac00\ud558\uae30\\n- Device Token \uc5bb\uae30\\n\\nAndroid \uae30\ucd08\uc138\ud305 \uad00\ub828\ud574\uc11c\ub294 [KOIN \uae43\ud5c8\ube0c \ub9c1\ud06c](https://github.com/BCSDLab/KOIN_ANDROID/commit/bbba9f724da8cffb2f2bdd46160888f54aa4386a)\uc640 [\ud30c\uc774\uc5b4\ubca0\uc774\uc2a4 \uacf5\uc2dd \ubb38\uc11c](https://firebase.google.com/docs/cloud-messaging/android/client?hl=ko&authuser=0&_gl=1*qq036s*_up*MQ..*_ga*MTc2MzkxMzYyOS4xNzEyNDc0MDE5*_ga_CW55HF8NVT*MTcxMjQ3NDAxOS4xLjEuMTcxMjQ3NDA4OC4wLjAuMA..)\ub97c \ucc38\uc870\ud574\uc8fc\uc138\uc694.\\n\\n\\n### \ud1a0\ud070 \uc5bb\uae30\\nFirebase API\ub97c \uc0ac\uc6a9\ud558\uc5ec Android \ud578\ub4dc\ud3f0\uc758 \ub514\ubc14\uc774\uc2a4 \ud1a0\ud070\uc744 \uc5bb\uc744 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \ud574\ub2f9 \ud0c0\uac9f\uc73c\ub85c \ud1a0\ud070\uc774 \ub4f1\ub85d\ub41c \ub514\ubc14\uc774\uc2a4\uc5d0\uac8c FCM\uc740 \uba54\uc2dc\uc9c0\ub97c \ubcf4\ub0bc \uc218 \uc788\uac8c \ub429\ub2c8\ub2e4. \\n```kotlin title=\\"MainActivity.kt\\"\\nFirebaseMessaging.getInstance().token.addOnCompleteListener { task ->\\n    if (!task.isSuccessful) {}\\n    val token = task.result\\n    Log.e(\\"device_token\\", \\"token : $token\\")\\n}\\n\\n```\\n\\n### FCM \uba54\uc2dc\uc9c0 \uc218\uc2e0\\n\\nFCM \uba54\uc2dc\uc9c0\ub97c `FirebaseMessagingService` API\ub97c \uc0ac\uc6a9\ud558\uc5ec \uba54\uc2dc\uc9c0\ub97c \uc218\uc2e0\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \\n```kotlin title=\\"KoinFirebaseMessagingService.kt\\"\\nclass KoinFirebaseMessagingService : FirebaseMessagingService() {\\n    override fun onMessageReceived(message: RemoteMessage) {\\n        super.onMessageReceived(message)\\n        message.data.let { data ->\\n            if (data.isNotEmpty()) {\\n                Log.e(\\"fcm_data\\", \\"notEmpty message.data : $data\\")\\n            }\\n        }\\n\\n        message.notification?.let { notification ->\\n            notification.title\\n            notification.body\\n            notification.clickAction\\n        }\\n    }\\n\\n    override fun onNewToken(token: String) {\\n        super.onNewToken(token)\\n    }\\n}\\n```\\n\\n:::note \uad81\uae08\ud55c \ubd80\ubd84, Firebase \uc5d0\uc11c \uc9c1\uc811 \ud14c\uc2a4\ud2b8\ud574\ubcfc \uc218 \uc788\ub294 \ub370, \uad73\uc774 \uc11c\ubc84\ub97c \uad6c\ucd95\ud558\uace0 \ud14c\uc2a4\ud2b8\ub97c \ud574\uc57c\ud558\ub294 \uc774\uc720\uac00 \uc788\ub098\uc694?\\n\\n: Firebase \uc5d0\uc11c \uc81c\uacf5\ud558\ub294 \ud14c\uc2a4\ud2b8\ub294 Notification \ud398\uc774\ub85c\ub4dc\ub9cc \uac00\uc9c0\uace0 \uc81c\ubaa9, \ub0b4\uc6a9, \uc774\ubbf8\uc9c0\uc5d0 \ub300\ud55c \uc54c\ub9bc\ub9cc \ubc1b\uc544\ubcfc \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\uc54c\ub9bc \ucc3d\uc744 \ud074\ub9ad\ud574\uc11c \ub2e4\ub978 \ud398\uc774\uc9c0\ub85c \uc774\ub3d9\ud558\uace0 \uc2f6\uac70\ub098, Firebase \uae30\uc874 \uc54c\ub9bc\uc744 \uc0ac\uc6a9\ud558\uc9c0\uc54a\uace0 \ucee4\uc2a4\ud140\ud558\uac8c \uc81c\uc791\ud558\ub824\uba74 \uc11c\ubc84 \uac1c\ubc1c\uc790 \ubd84\ub4e4\uc5d0\uac8c \uc694\uccad\ud574\uc57c\ud558\ub2c8 \uc774\ub97c \ud074\ub77c\uc774\uc5b8\ud2b8 \uac1c\ubc1c\uc790\uac00 \uc27d\uac8c \ud14c\uc2a4\ud2b8\ud574\ubcfc \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n:::\\n\\nFCM \uba54\uc2dc\uc9c0\ub97c \uc218\uc2e0\ud558\ub294 \ubc29\ubc95\uc740 \uacf5\uc2dd\ubb38\uc11c\uc5d0\uc11c\ub294 \ub2e4\uc74c\uacfc \uac19\uc774 \uc124\uba85\ud569\ub2c8\ub2e4.\\n<img src=\\"/img/@android/jkh_fcm/firebase_aos_message_kor.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"0px\\" }} />\\n\\n\uc74c.. \ud55c\uad6d\uc5b4 \ubcf4\ub2e4\ub294 \uc601\uc5b4\ub85c \ud655\uc778\ud574\ubcf4\uaca0\uc2b5\ub2c8\ub2e4. \\n<img src=\\"/img/@android/jkh_fcm/firebase_aos_message_eng.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"0px\\" }} />\\n\\n\uc0b4\ud3b4\ubcf4\uba74, \ud3ec\uadf8\ub77c\uc6b4\ub4dc \uc11c\ube44\uc2a4 \uc77c \ub54c\ub294 \uc571\uc774 \uc2e4\ud589\ub418\uace0 \uc788\uc744 \ub54c Notification \uacfc Data \uc5d0 \ub300\ud55c \ud398\uc774\ub85c\ub4dc\ub97c \uc218\uc2e0\ud569\ub2c8\ub2e4.\\n\ud558\uc9c0\ub9cc \ubc31\uadf8\ub77c\uc6b4\ub4dc \uc11c\ube44\uc2a4 \uc77c \ub54c\ub294 Notification \uc5d0 \ub300\ud55c \ud398\uc774\ub85c\ub294 System tray \ub85c \ube60\uc9c0\uace0 Data\uc5d0 \ub300\ud55c \ud398\uc774\ub85c\ub4dc\ub9cc \uc218\uc2e0\ud569\ub2c8\ub2e4.\\n\\n\ub2e4\uc74c\uacfc \uac19\uc774 \ud574\uc11d\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n- \uc571\uc774 \ud3ec\uadf8\ub77c\uc6b4\ub4dc \uc0c1\ud0dc\uc77c \ub54c\\n    - Notification & Data \ud398\uc774\ub85c\ub4dc \uc1a1\uc2e0\\n        - onMessageReceived \uc218\uc2e0\\n\\n- \uc571\uc774 \ubc31\uadf8\ub77c\uc6b4\ub4dc \uc0c1\ud0dc\uc77c \ub54c\\n    - Notification & Data \ud398\uc774\ub85c\ub4dc \uc1a1\uc2e0\\n        - onMessageReceived \uc218\uc2e0 \ubabb\ud568\\n    - Data \ud398\uc774\ub85c\ub4dc \uc1a1\uc2e0\\n        - onMessageReceived \uc218\uc2e0\\n\\n\ubb38\uc81c\ub294 \ubc31\uadf8\ub77c\uc6b4\ub4dc \uc0c1\ud0dc\uc77c \ub54c\uc785\ub2c8\ub2e4.\\n\uc571\uc774 \ubc31\uadf8\ub77c\uc6b4\ub4dc \uc0c1\ud0dc\uc774\uba70 Notification & Data \ud398\uc774\ub85c\ub4dc\ub97c \uc218\uc2e0\ud558\uc9c0 \ubabb\ud569\ub2c8\ub2e4. \uadf8 \uc774\uc720\ub294 Notification \uc740 System tray \uc5d0\uc11c \ub3d9\uc791\ud558\uba70 Firebase \uc5d0\uc11c \uae30\ubcf8\uc73c\ub85c \uc81c\uacf5\ud558\ub294 \uc54c\ub9bc\uc744 \uc0ac\uc6a9\ud558\uac8c \ub429\ub2c8\ub2e4. \uc989, \ud074\ub9ad\uc744 \ud558\ub354\ub77c\ub3c4 \uc544\ub798\uc640 \uac19\uc740 Intent-filter\uac00 \uc801\uc6a9\ub41c \ud398\uc774\uc9c0\ub85c \uc774\ub3d9\ud558\uac8c \ub429\ub2c8\ub2e4.\\n\\n```kotlin\\n<activity\\n    android:name=\\".ui.splash.SplashActivity\\"\\n    android:exported=\\"true\\"\\n    <intent-filter>\\n        <action android:name=\\"android.intent.action.MAIN\\"/>\\n        <action android:name=\\"android.intent.action.VIEW\\"/>\\n\\n        <category android:name=\\"android.intent.category.LAUNCHER\\"/>\\n    </intent-filter>\\n</activity>\\n```\\n\\n\uadf8\ub807\ub2e4\uba74 \uc544\ub798\uc640 \uac19\uc774 \uc758\ubb38\uc810 3\uac00\uc9c0\uac00 \uc0dd\uae41\ub2c8\ub2e4.\\n- \uc571\uc774 \ubc31\uadf8\ub77c\uc6b4\ub4dc\uc5d0 \uc788\uc744 \ub54c, message\ub97c \ubc1b\uc744 \uc218 \uc788\ub098?\\n- \uae30\uc874\uc5d0\ub294 Firebase\uac00 \uc81c\uacf5\ud558\ub294 \uc54c\ub9bc\uc744 \uc0ac\uc6a9\ud558\ub294\ub370, \uc54c\ub9bc\uc744 \ucee4\uc2a4\ud140\ud560 \uc218 \uc5c6\ub098?\\n- \uae30\uc874 Firebase \uc5d0\uc11c \uc81c\uacf5\ud558\ub294 \uc54c\ub9bc\uc744 \uc0ac\uc6a9\ud560 \ub54c, \uc54c\ub9bc\uc744 \ud074\ub9ad\ud588\uc744 \ub54c \uc6d0\ud558\ub294 View\ub85c \uc774\ub3d9\ud560 \uc218 \uc5c6\ub098?\\n\\n> **\uc571\uc774 \ubc31\uadf8\ub77c\uc6b4\ub4dc\uc5d0 \uc788\uc744 \ub54c, message\ub97c \ubc1b\uc744 \uc218 \uc788\ub098?**\\n> \\n\\nmessage\ub97c \ubc1b\uc744 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \ud558\uc9c0\ub9cc \uae30\uc874 \ubc29\ubc95\uc73c\ub85c \uc0ac\uc6a9\ud558\uba74 message\ub97c \ubc1b\uc744 \uc218 \uc5c6\uc744 \uac81\ub2c8\ub2e4.\\n\\n\uc5ec\uae30\uc11c \uc911\uc694\ud55c \ud3ec\uc778\ud2b8\ub294 \uc11c\ubc84\uc5d0\uc11c \ubcf4\ub0b4\uc8fc\ub294 message format\ub97c \uc798 \ubd10\uc57c\ud569\ub2c8\ub2e4.\\n\\n\uae30\uc874 message format \uc740 \ub2e4\uc74c\uacfc \uac19\uc2b5\ub2c8\ub2e4.\\n\\n```json\\n{\\n    \\"notification\\": {\\n        \\"title\\" : \\"koin title\\",\\n        \\"body\\" : \\"koin body\\"\\n    },\\n    \\"data\\" : {\\n        \\"koin_title\\" : \\"koin data title\\",\\n        \\"koin_body\\" : \\"koin data body\\"\\n    }\\n}\\n```\\nAndroid\uc5d0\uc11c\ub294 FCM\uc73c\ub85c\ubd80\ud130 message\ub97c \uc218\uc2e0\ud560 \ub54c, \ubc31\uadf8\ub77c\uc6b4\ub4dc\uc5d0\uc11c \uc218\uc2e0\ud558\ub294 \uacbd\uc6b0\uc640 \uae30\uc874 Firebase message format\uc5d0 \ub9de\uac8c \ucc98\ub9ac\ub418\ub294 \uacfc\uc815\uc774 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\uc774 \ubd80\ubd84\uc740 [**FCM \uacf5\uc2dd\ubb38\uc11c**](https://firebase.google.com/docs/cloud-messaging/android/receive?hl=ko)\ub97c \ucc38\uc870\ud558\uba74 \ub354 \uc790\uc138\ud788 \uc774\ud574\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\uc989, \uc704\uc640\uac19\uc740 message format\uc73c\ub85c \uc11c\ubc84\ub85c\ubd80\ud130 FCM\uc774 \ub3c4\ucc29\ud55c\ub2e4\uba74 \ubc31\uadf8\ub77c\uc6b4\ub4dc\uc5d0\uc11c\ub294 \uc544\uc27d\uac8c\ub3c4 \ub370\uc774\ud130\ub97c \ubc1b\uc744 \uc218 \uc5c6\uc2b5\ub2c8\ub2e4.\\n\\n\uadf8\ub807\ub2e4\uba74 \uc5b4\ub5bb\uac8c \ud574\uacb0\ud574\uc57c\ud560\uae4c\uc694?\\n\\n\uc815\ub2f5\uc740 notification field\ub97c \uc81c\uac70\ud558\ub294 \uac83\uc785\ub2c8\ub2e4. notification field\ub97c \uc81c\uac70\ud568\uc73c\ub85c\uc368, data field\uac00 \uc8fc FCM \uba54\uc2dc\uc9c0 \ud5e8\ub4e4\ub9c1 message format\uc774 \ub429\ub2c8\ub2e4. \uc774\ub294 \uc801\uc808\ud558\uac8c \uc0ac\uc6a9\ud55c\ub2e4\uba74 2\ubc88\uc5d0\uc11c \uc9c8\ubb38\ud55c **\uae30\uc874\uc5d0\ub294 Firebase\uac00 \uc81c\uacf5\ud558\ub294 \uc54c\ub9bc\uc744 \uc0ac\uc6a9\ud558\ub294\ub370, \uc54c\ub9bc\uc744 \ucee4\uc2a4\ud140\ud560 \uc218 \uc5c6\ub098?** \uc5d0 \ub300\ud55c \ub2f5\ubcc0\uc774 \ub429\ub2c8\ub2e4.\\n\\n\ubc31\uadf8\ub77c\uc6b4\ub4dc\uc5d0\uc11c \uc218\uc9d1\ud560 \uc218 \uc788\ub294 message format\uc740 \ub2e4\uc74c\uacfc \uac19\uc2b5\ub2c8\ub2e4.\\n```json\\n{\\n    \\"data\\" : {\\n        \\"koin_title\\" : \\"koin data title\\",\\n        \\"koin_body\\" : \\"koin data body\\"\\n    }\\n}\\n```\\nAndroid \uc5d0\uc11c\ub294 \uc544\ub798\uc640 \uac19\uc774 message \ub97c \uc218\uc2e0\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n```kotlin\\nmessage.data.let { data ->\\n    if (data.isNotEmpty()) {\\n       data\\n    }\\n}\\n```\\n> **\uae30\uc874\uc5d0\ub294 Firebase\uac00 \uc81c\uacf5\ud558\ub294 \uc54c\ub9bc\uc744 \uc0ac\uc6a9\ud558\ub294\ub370, \uc54c\ub9bc\uc744 \ucee4\uc2a4\ud140\ud560 \uc218 \uc5c6\ub098?**\\n> \\n\\n\uac00\ub2a5\ud569\ub2c8\ub2e4. \uae30\uc874 Firebase \uc54c\ub9bc\uc744 \uc0ac\uc6a9\ud558\uc9c0 \uc54a\uace0\ub3c4 \ucee4\uc2a4\ud140\ud55c \uc54c\ub9bc\uc744 \uc81c\uc791\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \uae30\uc874 Notification Builder\ub97c \uc0ac\uc6a9\ud558\uc5ec \uc54c\ub9bc\uc744 \uc81c\uc791\ud558\uace0 Channel(API 26) \ub97c \ub9cc\ub4e4\uba74 \ub429\ub2c8\ub2e4.\\n\\n\uac04\ub2e8\ud569\ub2c8\ub2e4. \uc704\uc5d0\uc11c \uc5b8\uae09\ud55c message format \uc911 notification field\ub97c \uc81c\uac70\ud558\uace0 data field\ub97c \uc0ac\uc6a9\ud558\uc5ec \ud574\ub2f9 data field \uc18d\uc131\uc744 \uc801\uc808\ud558\uac8c \uc0ac\uc6a9\ud558\uba74\ub429\ub2c8\ub2e4.\\n\\n\ud574\ub2f9 \ubd80\ubd84\uc740 \uc11c\ubc84\uc640\uc758 message formatting\uc744 \ub354 \uae34\ubc00\ud558\uac8c \ud574\uc57c\ud560 \uac83 \uac19\uc2b5\ub2c8\ub2e4.\\n\\n\\n> **\uae30\uc874 Firebase \uc5d0\uc11c \uc81c\uacf5\ud558\ub294 \uc54c\ub9bc\uc744 \uc0ac\uc6a9\ud560 \ub54c, \uc54c\ub9bc\uc744 \ud074\ub9ad\ud588\uc744 \ub54c \uc6d0\ud558\ub294 View\ub85c \uc774\ub3d9\ud560 \uc218 \uc5c6\ub098?**\\n> \\n\\n\uac00\ub2a5\ud569\ub2c8\ub2e4. \ud574\ub2f9 \ubd80\ubd84\uc740 Android message format\uc784\uc744 \uc54c\ub824\ub4dc\ub9bd\ub2c8\ub2e4.\\n\\nFCM message format \uc911 android field\uac00 \uc874\uc7ac\ud569\ub2c8\ub2e4.\\n\\n\ud574\ub2f9 field\uc5d0\ub294 \ub2e4\uc591\ud55c \uc18d\uc131\ub4e4\uc774 \uc874\uc7ac\ud558\ub294\ub370, \uc774 \uc911\uc5d0\uc11c clickAction \uc18d\uc131\uc774 \ubc14\ub85c \uae30\uc874 Firebase \uc54c\ub9bc\uc744 \ud074\ub9ad\ud588\uc744 \ub54c \ubc1c\uc0dd\ud558\ub294 \uc774\ubca4\ud2b8 \uc18d\uc131\uc785\ub2c8\ub2e4.\\n\\n\uae30\uc874\uc5d0\ub294 \uc544\ub798\uc640 \uac19\uc774 Main\uc73c\ub85c \uc774\ub3d9\ud558\uac8c \ub429\ub2c8\ub2e4.\\n```kotlin title=\\"AndroidManifest.xml\\"\\n<intent-filter>\\n  <action android:name=\\"android.intent.action.MAIN\\"/>\\n  <action android:name=\\"android.intent.action.VIEW\\"/>\\n\\n  <category android:name=\\"android.intent.category.LAUNCHER\\"/>\\n</intent-filter>\\n```\\n\\n\ud558\uc9c0\ub9cc \uc774\ub97c \uc801\uc808\ud558\uac8c \uc0ac\uc6a9\ud55c\ub2e4\uba74, \uac00\uace0\uc2f6\uc740 View\ub85c \uc774\ub3d9\ud558\ub294 Action\uc744 \uc6d0\ud558\ub294 \uc54c\ub9bc\uc5d0 \ub123\uc744 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\ub9cc\uc57d\uc5d0 \ub85c\uadf8\uc778\uc744 \ud558\ub77c\ub294 \uc54c\ub9bc\uc774 \ub3c4\ucc29\ud588\uace0, \ub85c\uadf8\uc778 \ud398\uc774\uc9c0\ub85c \uc774\ub3d9\ud558\ub294 \uacfc\uc815\uc744 \uc124\uba85\ud558\uaca0\uc2b5\ub2c8\ub2e4.\\n\\n\uc6b0\uc120 message format\uc740 \ub2e4\uc74c\uacfc \uac19\uc774 \uc9c4\ud589\ub429\ub2c8\ub2e4.\\n\\n```json\\n\\"android\\" : {\\n    \\"title\\" : \\"koin_android_title\\",\\n    \\"body\\" : \\"koin_android_body\\",\\n    \\"click_action\\" : \\"LOGIN_ACTIVITY\\"\\n}\\n```\\nclick_action\uc758 \uc18d\uc131 \uac12\uc740 \ud604\uc7ac LOGIN_ACTIVITY\ub85c \uc9c4\ud589\ud588\uc9c0\ub9cc \ud611\uc5c5 \uc2dc \uc54c\ub9bc \uba85\uc138\ub97c \uc9c4\ud589\ud558\uc5ec \ud1b5\uc77c\uc131\uc744 \ub9de\ucd9c \uc218 \uc788\uc744 \uac83 \uac19\uc2b5\ub2c8\ub2e4.(\ud611\uc5c5\ud558\uba74, apns, webpush \uc640 \uac19\uc774 iOS\uc640 Web\uc5d0\ub3c4 \uc54c\ub9bc\uc744 \ubcf4\ub0bc \uc218 \uc788\uae30 \ub54c\ubb38\uc785\ub2c8\ub2e4.)\\n\\n\uc6b0\uc120 LOGIN_ACTIVITY\ub77c\ub294 click_action \uc744 FCM\uc73c\ub85c \uc694\uccad\uc744 \ubcf4\ub0b4\uc5b4 \ud574\ub2f9 FCM\uc740 Android\uc5d0\uac8c message\ub97c \ubcf4\ub0b4\uac8c \ub429\ub2c8\ub2e4.\\n\\n\ub2e4\uc74c\uacfc \uac19\uc774 message\ub97c \ubc1b\uc744 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\uc571\uc774 \ucf1c\uc84c\uc744 \ub54c\uc785\ub2c8\ub2e4. \ub2e4\uc2dc \ub9ac\ub9c8\uc778\ub4dc \ud574\ubcf4\uba74 notification field \uac00 \uc544\ub2cc data field \ub9cc! \ubcf4\ub0b4\uc57c android \uc5d0\uc11c background \uc791\uc5c5\uc774 \uac00\ub2a5\ud574\uc9d1\ub2c8\ub2e4.\\n```kotlin title=\\"KoinFirebaseMessagingService.kt\\"\\nmessage.notification?.let { notification ->\\n    notification.title\\n    notification.body\\n    notification.clickAction\\n}\\n```\\n\\n\uadf8\ub807\ub2e4\uba74 click_action\uc744 \uc5b4\ub514\uc11c \ucc98\ub9ac\ud574\uc57c\ud558\ub098\uc694?\\n\\n\ud574\ub2f9 \ubd80\ubd84\uc740 \uae30\uc874\uc5d0 click_action\uc744 manifest \uc5d0\uc11c \ucc98\ub9ac\ud55c \uac83\uacfc \uac19\uc774 manifest\uc5d0\uc11c \ucc98\ub9ac\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n```kotlin title=\\"AndroidManifest.xml\\"\\n<activity\\n    android:name=\\".ui.login.LoginActivity\\"\\n    android:exported=\\"false\\"\\n    <intent-filter>\\n      <action android:name=\\"LOGIN_ACTIVITY\\"/>\\n      <category android:name=\\"android.intent.category.DEFAULT\\"/>\\n    </intent-filter>\\n</acitivity>\\n```\\n\uc704\uc640 \uac19\uc774 \ucc98\ub9ac\ub418\uba74, \uae30\uc874 Firebase \uc5d0\uc11c \uc81c\uacf5\ud558\ub294 \uc54c\ub9bc\uc744 \ud074\ub9ad\ud588\uc744 \ub54c, \ud574\ub2f9 \uc54c\ub9bc\uc758 message format\uc73c\ub85c android field \uc18d\uc131 \uc911 click_action \uac12\uc774 LOGIN_ACTIVITY \uc77c \ub54c \ub85c\uadf8\uc778 \ud398\uc774\uc9c0\ub85c \uc774\ub3d9\ud568\uc744 \uc54c \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\\n# \ud14c\uc2a4\ud2b8 with Postman\\n## HTTP Request \ub9cc\ub4e4\uae30\\nPostman \uc5d0\uc11c \uc11c\ubc84\uc5d0 \uc694\uccad\ud560 Reuqest\ub97c \ub9cc\ub4ed\ub2c8\ub2e4.\\n- \ub514\ubc14\uc774\uc2a4 \ud1a0\ud070\uc740 Android getToken \uc73c\ub85c\ubd80\ud130 \ubc1b\uc2b5\ub2c8\ub2e4.\\n- \uc81c\ubaa9\uacfc \ub0b4\uc6a9\uc740 \uc6d0\ud558\ub294 \ub300\ub85c \uc791\uc131\ud574\uc8fc\uba74 \ub429\ub2c8\ub2e4.\\n<img src=\\"/img/@android/jkh_fcm/postman_request.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"20px\\" }} />\\n\\n\\n\\n## \ubcf8\uaca9\uc801\uc778 \ud14c\uc2a4\ud2b8\\n\ud14c\uc2a4\ud2b8\uc5d0 \ub300\ud55c \uc804\uccb4\uc801\uc778 \ud50c\ub85c\uc6b0\ub294 \ub2e4\uc74c\uacfc \uac19\uc2b5\ub2c8\ub2e4.\\n\\n\\n1. \ucc98\uc74c\uc5d0 \uc9c4\ud589\ub418\uc5c8\ub358, \ub85c\uceec \uc11c\ubc84\ub97c \uc2e4\ud589\ud569\ub2c8\ub2e4. \\n<img src=\\"/img/@android/jkh_fcm/spring_boot_start.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"0px\\" }} />\\n\\n\\n2. \uc548\ub4dc\ub85c\uc774\ub4dc \ub514\ubc14\uc774\uc2a4 \ud1a0\ud070\uc744 \ubc1c\ud589\ud569\ub2c8\ub2e4.\\n```kotlin title=\\"MainActivity.kt\\"\\nFirebaseMessaging.getInstance().token.addOnCompleteListener { task ->\\n    if (!task.isSuccessful) {}\\n    val token = task.result\\n    Log.e(\\"device_token\\", \\"token : $token\\")\\n}\\n```\\n\\n3. Postman \uc744 \uc0ac\uc6a9\ud574\uc11c HTTP POST \uc694\uccad\uc744 \ubcf4\ub0c5\ub2c8\ub2e4.\\n\\n<img src=\\"/img/@android/jkh_fcm/postman_request.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"0px\\" }} />\\n\\n\\n4. \uc548\ub4dc\ub85c\uc774\ub4dc\uc5d0\uc11c FCM \uba54\uc2dc\uc9c0\ub97c \uc218\uc2e0\ud569\ub2c8\ub2e4.\\n\\n```kotlin title=\\"KoinFirebaseMessagingService.kt\\"\\n\\nclass KoinFirebaseMessagingService : FirebaseMessagingService() {\\n    override fun onMessageReceived(message: RemoteMessage) {\\n        super.onMessageReceived(message)\\n    }\\n}\\n```\\n\\n## \uc548\ub4dc\ub85c\uc774\ub4dc FCM \uba54\uc2dc\uc9c0 \uc218\uc2e0 \ud14c\uc2a4\ud2b8\\n### \uc77c\ubc18\uc801\uc778 \ud14c\uc2a4\ud2b8\\n- message format\\n    ```json\\n    {\\n        \\"notification\\" : {\\n            \\"title\\" : \\"koin title\\",\\n            \\"body\\" : \\"koin body\\"\\n        },\\n        \\"data\\" : {\\n            \\"koin_title\\" : \\"koin data title\\",\\n            \\"koin_body\\" : \\"koin data body\\"\\n        }\\n    }\\n    ```\\n- kotlin spring code\\n    ```kotlin title=\\"FcmMessage.kt\\"\\n    data class FcmMessage(\\n        val validate_only: Boolean = false,\\n        val message: Message\\n    )\\n\\n    data class Message(\\n        val notification: Notification,\\n        val data: Map<String,String>,\\n        val token: String,\\n    )\\n\\n    data class Notification(\\n        val title: String,\\n        val body: String,\\n    )\\n    ```\\n\\n    ```kotlin title=\\"FirebaseCloudMessagingService.kt\\"\\n    val notification = Notification(title = title, body = body)\\n    val data = mapOf(\\"koin_title\\" to \\"koin data title\\", \\"koin_body\\" to \\"koin data body\\")\\n    val message = Message(token = targetToken, notification = notification, data = data)\\n    ```\\n\\n- \uc571\uc774 \ud3ec\uadf8\ub77c\uc6b4\ub4dc \uc0c1\ud0dc\uc77c \ub54c \uba54\uc2dc\uc9c0 \uc218\uc2e0\\n<img src=\\"/img/@android/jkh_fcm/test1_1.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"0px\\" }} />\\n\\n\\n\\n- \uc571\uc774 \ubc31\uadf8\ub77c\uc6b4\ub4dc \uc0c1\ud0dc\uc77c \ub54c \uba54\uc2dc\uc9c0 \ubbf8\uc218\uc2e0\\n<img src=\\"/img/@android/jkh_fcm/test1_2.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"0px\\" }} />\\n\\n\\n\uc704\uc5d0\uc11c \uc0ac\uc9c4\uc73c\ub85c \ubcf4\uba74 \ud3ec\uadf8\ub77c\uc6b4\ub4dc \uc0c1\ud0dc\uc5d0\uc11c\ub294 \uba54\uc2dc\uc9c0\ub97c \uc218\uc2e0\ud569\ub2c8\ub2e4. \ud558\uc9c0\ub9cc \ubc31\uadf8\ub77c\uc6b4\ub4dc \uc0c1\ud0dc\uc5d0\uc11c\ub294 \uc54c\ub9bc\ucc3d\ub9cc \ub728\uace0 \uba54\uc2dc\uc9c0\ub97c \uc218\uc2e0\ud560 \uc218 \uc5c6\uc2b5\ub2c8\ub2e4.\\n\uc54c\ub9bc \ud074\ub9ad \uc2dc, Main-Launcher\ub85c \uc774\ub3d9\ud568\uc744 \uc54c \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n```kotlin title=\\"AndroidManifest.xml\\"\\n<activity\\n    android:name=\\".ui.splash.SplashActivity\\"\\n    android:exported=\\"true\\"\\n    <intent-filter>\\n        <action android:name=\\"android.intent.action.MAIN\\"/>\\n        <action android:name=\\"android.intent.action.VIEW\\"/>\\n\\n        <category android:name=\\"android.intent.category.LAUNCHER\\"/>\\n    </intent-filter>\\n</activity>\\n```\\n<img src=\\"/img/@android/jkh_fcm/test1_3.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"0px\\" }} />\\n\\n### \uc54c\ub9bc \ud074\ub9ad \uc561\uc158 \ud14c\uc2a4\ud2b8\\n\\n- message format\\n    ```json\\n    {\\n        \\"notification\\" : {\\n            \\"title\\" : \\"koin title\\",\\n            \\"body\\" : \\"koin body\\"\\n        },\\n        \\"data\\" : {\\n            \\"koin_title\\" : \\"koin data title\\",\\n            \\"koin_body\\" : \\"koin data body\\"\\n        },\\n        \\"android\\" : {\\n            \\"click_action\\" : \\"LOGIN_ACTIVITY\\"\\n        }\\n    }\\n    ```\\n- kotlin spring code\\n    ```kotlin title=\\"FcmMessage.kt\\"\\n    data class FcmMessage(\\n        val validate_only: Boolean = false,\\n        val message: Message\\n    )\\n\\n    data class Message(\\n        val notification: Notification,\\n        val data: Map<String,String>,\\n        val android: Android,\\n        val token: String,\\n    )\\n\\n    data class Notification(\\n        val title: String,\\n        val body: String,\\n    )\\n\\n    data class Android(\\n        val notification: AndroidNotification\\n    )\\n\\n    data class AndroidNotification(\\n        val click_action: String\\n    )\\n    ```\\n\\n    ```kotlin title=\\"FirebaseCloudMessagingService.kt\\"\\n    val notification = Notification(title = title, body = body)\\n    val data = mapOf(\\"koin_title\\" to \\"koin data title\\", \\"koin_body\\" to \\"koin data body\\")\\n    val android = Android(org.example.fcm_demo.AndroidNotification(\\"LOGIN_ACTIVITY\\"))\\n    val message = Message(token = targetToken, notification = notification, data = data, android = android)\\n    ```\\n\\n- \uc571\uc774 \ud3ec\uadf8\ub77c\uc6b4\ub4dc \uc0c1\ud0dc\uc77c \ub54c \uba54\uc2dc\uc9c0 \uc218\uc2e0\\n<img src=\\"/img/@android/jkh_fcm/test2_1.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"0px\\" }} />\\n\\n\uc704\uc5d0\uc11c \uc0ac\uc9c4\uc73c\ub85c \ubcf4\uba74 \ud3ec\uadf8\ub77c\uc6b4\ub4dc \uc0c1\ud0dc\uc5d0\uc11c\ub294 \uba54\uc2dc\uc9c0\ub97c \uc218\uc2e0\ud55c\ub2e4. \ud558\uc9c0\ub9cc \ubc31\uadf8\ub77c\uc6b4\ub4dc \uc0c1\ud0dc\uc5d0\uc11c\ub294 \uc54c\ub9bc\ucc3d\ub9cc \ub728\uace0 \uba54\uc2dc\uc9c0\ub97c \uc218\uc2e0\ud560 \uc218 \uc5c6\uc2b5\ub2c8\ub2e4.\\n\uccab \ubc88\uc9f8 \ud14c\uc2a4\ud2b8\uc640 \uac19\uc740 \ub9e4\ucee4\ub2c8\uc998\uc785\ub2c8\ub2e4. \ud558\uc9c0\ub9cc \uc54c\ub9bc\uc744 \ud074\ub9ad\ud588\uc744 \ub54c\ub294 \ub2e4\ub985\ub2c8\ub2e4.\\n\uc6d0\ud558\ub294 \ud074\ub9ad \uc561\uc158 \uc18d\uc131\uc744 \uc124\uc815\ud568\uc73c\ub85c\uc368 \uc6d0\ud558\ub294 Activity\ub85c \uc774\ub3d9\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n```kotlin title=\\"AndroidManifest.xml\\"\\n<activity\\n    android:name=\\".ui.login.LoginActivity\\"\\n    android:exported=\\"false\\"\\n    <intent-filter>\\n        <action android:name=\\"LOGIN_ACTIVITY\\"/>\\n        <category android:name=\\"android.intent.category.DEFAULT\\"/>\\n    </intent-filter>\\n</activity>\\n```\\n\\n<img src=\\"/img/@android/jkh_fcm/test2_3.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"0px\\" }} />\\n\\n### \ubc31\uadf8\ub77c\uc6b4\ub4dc \uba54\uc2dc\uc9c0 \uc218\uc2e0 \ud14c\uc2a4\ud2b8\\n- message format\\n    ```json\\n    {\\n        \\"data\\" : {\\n            \\"koin_title\\" : \\"koin data title\\",\\n            \\"koin_body\\" : \\"koin data body\\"\\n        }\\n    }\\n    ```\\n- kotlin spring code\\n    ```kotlin title=\\"FcmMessage.kt\\"\\n    data class FcmMessage(\\n        val validate_only: Boolean = false,\\n        val message: Message\\n    )\\n\\n    data class Message(\\n        val data: Map<String,String>,\\n        val token: String,\\n    )\\n    ```\\n    ```kotlin title=\\"FirebaseCloudMessagingService.kt\\"\\n    val data = mapOf(\\"koin_title\\" to \\"koin data title\\", \\"koin_body\\" to \\"koin data body\\")\\n    val message = Message(token = targetToken, data = data)\\n    ```\\n\\n- \uc571\uc774 \ubc31\uadf8\ub77c\uc6b4\ub4dc \uc0c1\ud0dc\uc77c \ub54c \uba54\uc2dc\uc2dc \uc218\uc2e0\\n<img src=\\"/img/@android/jkh_fcm/test3.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"0px\\" }} />\\n\\n\uc0ac\uc9c4\ucc98\ub7fc \uc571\uc774 \ubc31\uadf8\ub77c\uc6b4\ub4dc \uc0c1\ud0dc\uc77c \ub54c, data \ud398\uc774\ub85c\ub4dc\uac00 \uc798 \uc218\uc2e0\ub418\ub294 \uac83\uc744 \uc54c \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\ud558\uc9c0\ub9cc \uc54c\ub9bc\ucc3d\uc740 \ub728\uc9c0 \uc54a\uc2b5\ub2c8\ub2e4. \uc989, \uc6d0\ud558\ub294 \uc54c\ub9bc\ucc3d\uc744 \ucee4\uc2a4\ud140\ud558\uac8c \uc81c\uc791\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n## \uc54c\ub9bc \uae30\ub2a5 \uba85\uc138\\n\\"\ucf54\uc778\\"\uc5d0\uc11c\ub294 \uc54c\ub9bc \uae30\ub2a5 \uba85\uc138\ub97c \ub2e4\uc74c\uacfc \uac19\uc774 \ud45c\ub85c \ub098\ud0c0\ub0b4\uc5b4 \uc9c4\ud589\ud560 \uc608\uc815\uc785\ub2c8\ub2e4!\\n<img src=\\"/img/@android/jkh_fcm/excel.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ marginBottom: \\"20px\\" }} />\\n\\n\\n\\n# \ucc38\uc870\\n- Android FCM Code\\n[KOIN Github(branch:fcm-setting) \ucc38\uc870](https://github.com/BCSDLab/KOIN_ANDROID/tree/feature/fcm-setting)\\n\\n- Kotlin Spring Boot Code\\n[\uac1c\uc778 \ub808\ud3ec\uc9c0\ud1a0\ub9ac Github \ucc38\uc870](https://github.com/Jokwanhee/fcm-server)\\n\\n- FCM server with Kotin Spring Boot\\n[\ucc38\uc870\ud55c \ube14\ub85c\uadf8](https://mopil.tistory.com/129)"}]}')}}]);